#!/bin/bash set -e PROJECT_DIR="WeChat" PACKAGE="com.wechat.messenger" PACKAGE_PATH="com/wechat/messenger" rm -rf "$PROJECT_DIR" mkdir -p "$PROJECT_DIR" cd "$PROJECT_DIR" # ─── DIRECTORY STRUCTURE ─────────────────────────────────────────────────────── mkdir -p app/src/main/java/$PACKAGE_PATH/{activities,adapters,database/{dao,entities},fragments,managers,models,receivers,services,utils,viewmodels,workers} mkdir -p app/src/main/res/{anim,animator,drawable,drawable-v24,layout,menu,mipmap-hdpi,mipmap-mdpi,mipmap-xhdpi,mipmap-xxhdpi,mipmap-xxxhdpi,values,values-night,xml,raw} # ─── GRADLE WRAPPER ──────────────────────────────────────────────────────────── mkdir -p gradle/wrapper cat > gradle/wrapper/gradle-wrapper.properties <<'EOF' distributionBase=GRADLE_USER_HOME distributionPath=wrapper/dists distributionUrl=https\://services.gradle.org/distributions/gradle-8.2-bin.zip zipStoreBase=GRADLE_USER_HOME zipStorePath=wrapper/dists EOF cat > gradle/wrapper/gradle-wrapper.jar.b64 <<'EOF' EOF cat > gradlew <<'GRADLEW' #!/bin/sh APP_HOME="$(cd "$(dirname "$0")" && pwd)" CLASSPATH="$APP_HOME/gradle/wrapper/gradle-wrapper.jar" exec java -classpath "$CLASSPATH" org.gradle.wrapper.GradleWrapperMain "$@" GRADLEW chmod +x gradlew # Download gradle wrapper jar curl -sL "https://github.com/gradle/gradle/raw/v8.2.0/gradle/wrapper/gradle-wrapper.jar" \ -o gradle/wrapper/gradle-wrapper.jar 2>/dev/null || \ wget -q "https://github.com/gradle/gradle/raw/v8.2.0/gradle/wrapper/gradle-wrapper.jar" \ -O gradle/wrapper/gradle-wrapper.jar 2>/dev/null || true # If download failed, use gradlew script that downloads itself cat > gradlew <<'GRADLEW' #!/bin/sh set -e APP_HOME="$(cd "$(dirname "$0")" && pwd -P)" WRAPPER_JAR="$APP_HOME/gradle/wrapper/gradle-wrapper.jar" if [ ! -f "$WRAPPER_JAR" ]; then mkdir -p "$APP_HOME/gradle/wrapper" curl -sL "https://services.gradle.org/distributions/gradle-wrapper-8.2.jar" \ -o "$WRAPPER_JAR" 2>/dev/null || \ wget -q "https://services.gradle.org/distributions/gradle-wrapper-8.2.jar" \ -O "$WRAPPER_JAR" 2>/dev/null || true fi exec java -classpath "$WRAPPER_JAR" org.gradle.wrapper.GradleWrapperMain "$@" GRADLEW chmod +x gradlew # ─── SETTINGS.GRADLE ─────────────────────────────────────────────────────────── cat > settings.gradle <<'EOF' pluginManagement { repositories { google() mavenCentral() gradlePluginPortal() } } dependencyResolutionManagement { repositoriesMode.set(RepositoriesMode.FAIL_ON_PROJECT_REPOS) repositories { google() mavenCentral() maven { url 'https://jitpack.io' } } } rootProject.name = "WeChat" include ':app' EOF # ─── ROOT BUILD.GRADLE ───────────────────────────────────────────────────────── cat > build.gradle <<'EOF' buildscript { repositories { google() mavenCentral() } dependencies { classpath 'com.android.tools.build:gradle:8.2.0' classpath 'com.google.gms:google-services:4.4.0' } } plugins { id 'com.android.application' version '8.2.0' apply false id 'com.google.gms.google-services' version '4.4.0' apply false } EOF # ─── APP BUILD.GRADLE ────────────────────────────────────────────────────────── cat > app/build.gradle <<'EOF' plugins { id 'com.android.application' id 'com.google.gms.google-services' } android { namespace 'com.wechat.messenger' compileSdk 34 defaultConfig { applicationId "com.wechat.messenger" minSdk 24 targetSdk 34 versionCode 1 versionName "1.0" multiDexEnabled true } signingConfigs { release { storeFile file('../keystore/release.keystore') storePassword 'wechat123' keyAlias 'wechat' keyPassword 'wechat123' } } buildTypes { release { minifyEnabled false signingConfig signingConfigs.release proguardFiles getDefaultProguardFile('proguard-android-optimize.txt'), 'proguard-rules.pro' } debug { applicationIdSuffix ".debug" } } compileOptions { sourceCompatibility JavaVersion.VERSION_17 targetCompatibility JavaVersion.VERSION_17 } packagingOptions { exclude 'META-INF/DEPENDENCIES' exclude 'META-INF/LICENSE' exclude 'META-INF/LICENSE.txt' exclude 'META-INF/NOTICE' exclude 'META-INF/NOTICE.txt' pickFirst 'lib/x86/libc++_shared.so' pickFirst 'lib/x86_64/libc++_shared.so' pickFirst 'lib/armeabi-v7a/libc++_shared.so' pickFirst 'lib/arm64-v8a/libc++_shared.so' } } dependencies { implementation platform('com.google.firebase:firebase-bom:32.7.0') implementation 'com.google.firebase:firebase-auth' implementation 'com.google.firebase:firebase-database' implementation 'com.google.firebase:firebase-messaging' implementation 'com.google.android.material:material:1.11.0' implementation 'androidx.appcompat:appcompat:1.6.1' implementation 'androidx.constraintlayout:constraintlayout:2.1.4' implementation 'androidx.recyclerview:recyclerview:1.3.2' implementation 'androidx.cardview:cardview:1.0.0' implementation 'androidx.swiperefreshlayout:swiperefreshlayout:1.1.0' implementation 'androidx.room:room-runtime:2.6.1' annotationProcessor 'androidx.room:room-compiler:2.6.1' implementation 'androidx.work:work-runtime:2.9.0' implementation 'androidx.lifecycle:lifecycle-viewmodel:2.7.0' implementation 'androidx.lifecycle:lifecycle-livedata:2.7.0' implementation 'androidx.lifecycle:lifecycle-runtime:2.7.0' implementation 'androidx.multidex:multidex:2.0.1' implementation 'com.github.bumptech.glide:glide:4.16.0' annotationProcessor 'com.github.bumptech.glide:compiler:4.16.0' implementation 'com.journeyapps:zxing-android-embedded:4.3.0' implementation 'com.google.zxing:core:3.5.2' implementation 'org.webrtc:google-webrtc:1.0.32006' implementation 'com.facebook.shimmer:shimmer:0.5.0' implementation 'de.hdodenhof:circleimageview:3.1.0' implementation 'androidx.viewpager2:viewpager2:1.0.0' implementation 'androidx.fragment:fragment:1.6.2' } EOF # ─── PROGUARD ────────────────────────────────────────────────────────────────── cat > app/proguard-rules.pro <<'EOF' -keep class com.wechat.messenger.** { *; } -keep class com.google.firebase.** { *; } -keep class org.webrtc.** { *; } -dontwarn org.webrtc.** -keep class com.google.zxing.** { *; } EOF # ─── GOOGLE-SERVICES.JSON ──────