ty android:name=".activities.CallActivity" android:exported="false" android:screenOrientation="portrait" android:showOnLockScreen="true" android:turnScreenOn="true" android:theme="@style/Theme.WeChat.Call"/> <activity android:name=".activities.IncomingCallActivity" android:exported="false" android:screenOrientation="portrait" android:showOnLockScreen="true" android:turnScreenOn="true" android:theme="@style/Theme.WeChat.Call"/> <activity android:name=".activities.QRScanActivity" android:exported="false" android:screenOrientation="portrait"/> <activity android:name=".activities.EditProfileActivity" android:exported="false" android:screenOrientation="portrait" android:windowSoftInputMode="adjustResize"/> <activity android:name=".activities.FriendRequestsActivity" android:exported="false" android:screenOrientation="portrait"/> <activity android:name=".activities.SettingsActivity" android:exported="false" android:screenOrientation="portrait"/> <service android:name=".services.WeChatFirebaseMessagingService" android:exported="false"> <intent-filter> <action android:name="com.google.firebase.MESSAGING_EVENT"/> </intent-filter> </service> <service android:name=".services.CallService" android:exported="false" android:foregroundServiceType="camera|microphone"/> <receiver android:name=".receivers.NotificationActionReceiver" android:exported="false"/> <receiver android:name=".receivers.BootReceiver" android:exported="true"> <intent-filter> <action android:name="android.intent.action.BOOT_COMPLETED"/> </intent-filter> </receiver> <provider android:name="androidx.core.content.FileProvider" android:authorities="com.wechat.messenger.fileprovider" android:exported="false" android:grantUriPermissions="true"> <meta-data android:name="android.support.FILE_PROVIDER_PATHS" android:resource="@xml/file_paths"/> </provider> </application> </manifest> EOF # ─── MODELS ──────────────────────────────────────────────────────────────────── cat > app/src/main/java/$PACKAGE_PATH/models/User.java <