tent; } public String getImageBase64() { return imageBase64; } public void setImageBase64(String imageBase64) { this.imageBase64 = imageBase64; } public String getThumbnailBase64() { return thumbnailBase64; } public void setThumbnailBase64(String thumbnailBase64) { this.thumbnailBase64 = thumbnailBase64; } public String getVoiceBase64() { return voiceBase64; } public void setVoiceBase64(String voiceBase64) { this.voiceBase64 = voiceBase64; } public double getLatitude() { return latitude; } public void setLatitude(double latitude) { this.latitude = latitude; } public double getLongitude() { return longitude; } public void setLongitude(double longitude) { this.longitude = longitude; } public long getTimestamp() { return timestamp; } public void setTimestamp(long timestamp) { this.timestamp = timestamp; } public int getStatus() { return status; } public void setStatus(int status) { this.status = status; } public boolean isEdited() { return isEdited; } public void setEdited(boolean edited) { isEdited = edited; } public boolean isDeleted() { return isDeleted; } public void setDeleted(boolean deleted) { isDeleted = deleted; } public String getReplyToMessageId() { return replyToMessageId; } public void setReplyToMessageId(String replyToMessageId) { this.replyToMessageId = replyToMessageId; } public String getReplyToContent() { return replyToContent; } public void setReplyToContent(String replyToContent) { this.replyToContent = replyToContent; } public String getReplyToSenderId() { return replyToSenderId; } public void setReplyToSenderId(String replyToSenderId) { this.replyToSenderId = replyToSenderId; } public boolean isStarred() { return isStarred; } public void setStarred(boolean starred) { isStarred = starred; } public Map<String, String> getReactions() { return reactions; } public void setReactions(Map<String, String> reactions) { this.reactions = reactions; } public long getEditedAt() { return editedAt; } public void setEditedAt(long editedAt) { this.editedAt = editedAt; } } EOF cat > app/src/main/java/$PACKAGE_PATH/models/Chat.java <<'EOF' package com.wechat.messenger.models; import com.google.firebase.database.IgnoreExtraProperties; import java.io.Serializable; @IgnoreExtraProperties public class Chat implements Serializable { private String chatId; private String otherUserId; private String otherUserName; private String otherUserImage; private String lastMessage; private String lastMessageType; private long lastMessageTime; private int unreadCount; private boolean isOnline; private long lastSeen; private boolean isTyping; public Chat() {} public String getChatId() { return chatId; } public void setChatId(String chatId) { this.chatId = chatId; } public String getOtherUserId() { return otherUserId; } public void setOtherUserId(String otherUserId) { this.otherUserId = otherUserId; } public String getOtherUserName() { return otherUserName; } public void setOtherUserName(String otherUserName) { this.otherUserName = otherUserName; } public String getOtherUserImage() { return otherUserImage; } public void setOtherUserImage(String otherUserImage) { this.otherUserImage = otherUserImage; } public String getLastMessage() { return lastMessage; } public void setLastMessage(String lastMessage) { this.lastMessage = lastMessage; } public String getLastMessageType() { return lastMessageType; } public void setLastMessageType(String lastMessageType) { this.lastMessageType = lastMessageType; } public long getLastMessageTime() { return lastMessageTime; } public void setLastMessageTime(long lastMessageTime) { this.lastMessageTime = lastMessageTime; } public int getUnreadCount() { return unreadCount; } public void setUnreadCount(int unreadCount) { this.unreadCount = unreadCount; } public boolean isOnline() { return isOnline; } public void setOnline(boolean online) { isOnline = online; } public long getLastSeen() { return lastSeen; } public void setLastSeen(long lastSeen) { this.lastSeen = lastSeen; } public boolean isTyping() { return isTyping; } public void setTyping(boolean typing) { isTyping = typing; } } EOF cat > app/src/main/java/$PACKAGE_PATH/models/FriendRequest.java <<'EOF' package com.wechat.messenger.models; import com.google.firebase.database.IgnoreExtraProperties; import java.io.Serializable; @IgnoreExtraProperties public class FriendRequest implements Serializable { private String requestId; private String fromUserId; private String fromAuthUid; private String fromName; private String fromImage; private String toUserId; private String toAuthUid; private String status; private long timestamp; public static final String STATUS_PENDING = "pending"; public static final String STATUS_ACCEPTED = "accepted"; public static final String STATUS_REJECTED = "rejected"; public FriendRequest() {} public String getRequestId() { return requestId; } public void setRequestId(String requestId) { this.requestId = requestId; } public String getFromUserId() { return fromUserId; } public void setFromUserId(String fromUserId) { this.fromUserId = fromUserId; } public String getFromAuthUid() { return fromAuthUid; } public void setFromAuthUid(String fromAuthUid) { this.fromAuthUid = fromAuthUid; } public String getFromName() { return fromName; } public void setFromName(String fromName) { this.fromName = fromName; } public String getFromImage() { return fromImage; } public void setFromImage(String fromImage) { this.fromImage = fromImage; } public String getToUserId() { return toUserId; } public void setToUserId(String toUserId) { this.toUserId = toUserId; } public String getToAuthUid() { return toAuthUid; } public void setToAuthUid(String toAuthUid) { this.toAuthUid = toAuthUid; } public String getStatus() { return status; } public void setStatus(String status) { this.status = status; } public long getTimestamp() { return timestamp; } public void setTimestamp(long timestamp) { this.timestamp = timestamp; } } EOF cat > app/src/main/java/$PACKAGE_PATH/models/CallData.java <<'EOF' package com.wechat.messenger.models; import com.google.firebase.database.IgnoreExtraProperties; import java.io.Serializable; @IgnoreExtraProperties public class CallData implements Serializable { private String callId; private String callerId; private String callerName; private String callerImage; private String receiverId; private String type; private String status; private String offer; private String answer; private long timestamp; public static final String TYPE_VOICE = "voice"; public static final String TYPE_VIDEO = "video"; public static final String STATUS_RINGING = "ringing"; public static final String STATUS_ACCEPTED = "accepted"; public static final String STATUS_REJECTED = "rejected"; public static final String STATUS_ENDED = "ended"; public static final String STATUS_MISSED = "missed"; public CallData() {} public String getCallId() { return callId; } public void setCallId(String callId) { this.callId = callId; } public String getCallerId() { return callerId; } public void setCallerId(String callerId) { this.callerId = callerId; } public String getCallerName() { return callerName; } public void setCallerName(String callerName) { this.callerName = callerName; } public String getCallerImage() { return callerImage; } public void setCallerImage(String callerImage) { this.callerImage = callerImage; } public String getReceiverId() { return receiverId; } public void setReceiverId(String receiverId) { this.receiverId = receiverId; } public String getType() { return type; } public void setType(String type) { this.type = type; } public String getStatus() { return status; } public void setStatus(String status) { this.status = status; } public String getOffer() { return offer; } public void setOffer(String offer) { this.offer = offer; } public String getAnswer() { return answer; } public void setAnswer(String answer) { this.answer = answer; } public long getTimestamp() { return timestamp; } public void setTimestamp(long timestamp) { this.timestamp = timestamp; } } EOF # ─── DATABASE ENTITIES ──────────────────