ic static String encodeImageToBase64(Context context, Uri imageUri, int maxSize) { try { InputStream inputStream = context.getContentResolver().openInputStream(imageUri); if (inputStream == null) return null; Bitmap bitmap = BitmapFactory.decodeStream(inputStream); inputStream.close(); if (bitmap == null) return null; return compressAndEncode(bitmap, maxSize); } catch (Exception e) { e.printStackTrace(); return null; } } public static String compressAndEncode(Bitmap bitmap, int maxSize) { try { int quality = 90; ByteArrayOutputStream baos = new ByteArrayOutputStream(); bitmap.compress(Bitmap.CompressFormat.JPEG, quality, baos); while (baos.toByteArray().length > maxSize && quality > 10) { quality -= 10; baos.reset(); bitmap.compress(Bitmap.CompressFormat.JPEG, quality, baos); } if (baos.toByteArray().length > maxSize) { int ratio = (int) Math.sqrt((double) maxSize / baos.toByteArray().length * 100); int newWidth = bitmap.getWidth() * ratio / 100; int newHeight = bitmap.getHeight() * ratio / 100; if (newWidth > 0 && newHeight > 0) { Bitmap scaled = Bitmap.createScaledBitmap(bitmap, newWidth, newHeight, true); baos.reset(); scaled.compress(Bitmap.CompressFormat.JPEG, 80, baos); scaled.recycle(); } } byte[] bytes = baos.toByteArray(); return Base64.encodeToString(bytes, Base64.DEFAULT); } catch (Exception e) { e.printStackTrace(); return null; } } public static String generateThumbnail(String base64Image) { try { byte[] decodedBytes = Base64.decode(base64Image, Base64.DEFAULT); BitmapFactory.Options options = new BitmapFactory.Options(); options.inSampleSize = 8; Bitmap bitmap = BitmapFactory.decodeByteArray(decodedBytes, 0, decodedBytes.length, options); if (bitmap == null) return null; Bitmap thumbnail = Bitmap.createScaledBitmap(bitmap, Constants.THUMBNAIL_SIZE, Constants.THUMBNAIL_SIZE, true); bitmap.recycle(); ByteArrayOutputStream baos = new ByteArrayOutputStream(); thumbnail.compress(Bitmap.CompressFormat.JPEG, 60, baos); thumbnail.recycle(); return Base64.encodeToString(baos.toByteArray(), Base64.DEFAULT); } catch (Exception e) { e.printStackTrace(); return null; } } public static Bitmap decodeBase64ToBitmap(String base64) { if (base64 == null || base64.isEmpty()) return null; try { byte[] decodedBytes = Base64.decode(base64, Base64.DEFAULT); BitmapFactory.Options options = new BitmapFactory.Options(); options.inPreferredConfig = Bitmap.Config.RGB_565; return BitmapFactory.decodeByteArray(decodedBytes, 0, decodedBytes.length, options); } catch (OutOfMemoryError e) { try { byte[] decodedBytes = Base64.decode(base64, Base64.DEFAULT); BitmapFactory.Options options = new BitmapFactory.Options(); options.inSampleSize = 2; options.inPreferredConfig = Bitmap.Config.RGB_565; return BitmapFactory.decodeByteArray(decodedBytes, 0, decodedBytes.length, options); } catch (Exception ex) { return null; } } catch (Exception e) { e.printStackTrace(); return null; } } public static void loadBase64Image(Context context, String base64, ImageView imageView, int placeholder) { if (base64 == null || base64.isEmpty()) { imageView.setImageResource(placeholder); return; } try { byte[] decodedBytes = Base64.decode(base64, Base64.DEFAULT); Glide.with(context) .load(decodedBytes) .diskCacheStrategy(DiskCacheStrategy.ALL) .placeholder(placeholder) .error(placeholder) .circleCrop() .into(imageView); } catch (Exception e) { imageView.setImageResource(placeholder); } } public static void loadBase64ImageRaw(Context context, String base64, ImageView imageView) { if (base64 == null || base64.isEmpty()) { imageView.setImageResource(android.R.drawable.ic_menu_gallery); return; } try { byte[] decodedBytes = Base64.decode(base64, Base64.DEFAULT); Glide.with(context) .load(decodedBytes) .diskCacheStrategy(DiskCacheStrategy.ALL) .placeholder(android.R.drawable.ic_menu_gallery) .into(imageView); } catch (Exception e) { imageView.setImageResource(android.R.drawable.ic_menu_gallery); } } } EOF cat > app/src/main/java/$PACKAGE_PATH/utils/DateUtils.java <<'EOF' package com.wechat.messenger.utils; import java.text.SimpleDateFormat; import java.util.Calendar; import java.util.Date; import java.util.Locale; public class DateUtils { public static String formatMessageTime(long timestamp) { Calendar now = Calendar.getInstance(); Calendar msgTime = Calendar.getInstance(); msgTime.setTimeInMillis(timestamp); if (now.get(Calendar.DATE) == msgTime.get(Calendar.DATE)) { return new SimpleDateFormat("hh:mm a", Locale.getDefault()).format(new Date(timestamp)); } else if (now.get(Calendar.DATE) - msgTime.get(Calendar.DATE) == 1) { return "Yesterday"; } else { return new SimpleDateFormat("dd/MM/yyyy", Locale.getDefault()).format(new Date(timestamp)); } } public static String formatLastSeen(long timestamp) { if (timestamp == 0) return "last seen a while ago"; Calendar now = Calendar.getInstance(); Calendar lastSeen = Calendar.getInstance(); lastSeen.setTimeInMillis(timestamp); if (now.get(Calendar.DATE) == lastSeen.get(Calendar.DATE)) { return "last seen today at " + new SimpleDateFormat("hh:mm a", Locale.getDefault()).format(new Date(timestamp)); } else if (now.get(Calendar.DATE) - lastSeen.get(Calendar.DATE) == 1) { return "last seen yesterday at " + new SimpleDateFormat("hh:mm a", Locale.getDefault()).format(new Date(timestamp)); } else { return "last seen " + new SimpleDateFormat("dd/MM/yyyy", Locale.getDefault()).format(new Date(timestamp)); } } public static String formatCallDuration(long seconds) { long h = seconds / 3600; long m = (seconds % 3600) / 60; long s = seconds % 60; if (h > 0) return String.format(Locale.getDefault(), "%02d:%02d:%02d", h, m, s); return String.format(Locale.getDefault(), "%02d:%02d", m, s); } public static String formatChatListTime(long timestamp) { Calendar now = Calendar.getInstance(); Calendar msgTime = Calendar.getInstance(); msgTime.setTimeInMillis(timestamp); if (now.get(Calendar.DATE) == msgTime.get(Calendar.DATE)) { return new SimpleDateFormat("hh:mm a", Locale.getDefault()).format(new Date(timestamp)); 