Trace(); } } public void sendMessage(Message message, DatabaseReference.CompletionListener listener) { try { DatabaseReference ref = getMessagesRef(message.getChatId()).child(message.getMessageId()); ref.setValue(message, listener); } catch (Exception e) { if (listener != null) listener.onComplete(new DatabaseException("Send failed"), null); } } public void updateChatList(String uid, Chat chat) { try { getChatsRef(uid).child(chat.getChatId()).setValue(chat); } catch (Exception e) { e.printStackTrace(); } } public void generateUniqueUserId(UserIdCallback callback) { String candidateId = ChatUtils.generateNumericId(); getUserIdsRef().child(candidateId).addListenerForSingleValueEvent(new ValueEventListener() { @Override public void onDataChange(DataSnapshot snapshot) { if (snapshot.exists()) { generateUniqueUserId(callback); } else { callback.onGenerated(candidateId); } } @Override public void onCancelled(DatabaseError error) { callback.onGenerated(ChatUtils.generateNumericId()); } }); } public interface UserIdCallback { void onGenerated(String userId); } } EOF # ─── WEBRTC MANAGER ──────────────────────────────────────────────────────────── cat > app/src/main/java/$PACKAGE_PATH/managers/WebRTCManager.java <<'EOF' package com.wechat.messenger.managers; import android.content.Context; import android.util.Log; import com.google.firebase.database.*; import com.wechat.messenger.utils.Constants; import org.webrtc.*; import java.util.*; public class WebRTCManager { private static final String TAG = "WebRTCManager"; private Context context; private PeerConnectionFactory peerConnectionFactory; private PeerConnection peerConnection; private VideoTrack localVideoTrack; private AudioTrack localAudioTrack; private VideoSource videoSource; private AudioSource audioSource; private EglBase eglBase; private SurfaceViewRenderer localRenderer; private SurfaceViewRenderer remoteRenderer; private WebRTCListener listener; private String callId; private boolean isInitiator; private boolean isVideoCall; private boolean isMuted = false; private boolean isSpeakerOn = true; private boolean isCameraOff = false; private boolean isFrontCamera = true; private MediaConstraints mediaConstraints; private List<PeerConnection.IceServer> iceServers; private DatabaseReference iceCandidatesRef; private List<IceCandidate> pendingCandidates = new ArrayList<>(); public interface WebRTCListener { void onLocalStream(VideoTrack videoTrack); void onRemoteStream(VideoTrack videoTrack); void onCallConnected(); void onCallDisconnected(); void onCallFailed(String reason); void onIceCandidateGenerated(IceCandidate candidate); } public WebRTCManager(Context context, boolean isVideoCall) { this.context = context; this.isVideoCall = isVideoCall; setupIceServers(); } private void setupIceServers() { iceServers = new ArrayList<>(); iceServers.add(PeerConnection.IceServer.builder(Constants.STUN_SERVER).createIceServer()); iceServers.add(PeerConnection.IceServer.builder(Constants.STUN_SERVER_2).createIceServer()); } public void initialize(EglBase eglBase) { this.eglBase = eglBase; try { PeerConnectionFactory.InitializationOptions initOptions = PeerConnectionFactory.InitializationOptions.builder(context) .setEnableInternalTracer(false) .createInitializationOptions(); PeerConnectionFactory.initialize(initOptions); PeerConnectionFactory.Options options = new PeerConnectionFactory.Options(); peerConnectionFactory = PeerConnectionFactory.builder() .setOptions(options) .setVideoDecoderFactory(new DefaultVideoDecoderFactory(eglBase.getEglBaseContext())) .setVideoEncoderFactory(new DefaultVideoEncoderFactory(eglBase.getEglBaseContext(), true, true)) .createPeerConnectionFactory(); mediaConstraints = new MediaConstraints(); mediaConstraints.mandatory.add(new MediaConstraints.KeyValuePair("OfferToReceiveAudio", "true")); mediaConstraints.mandatory.add(new MediaConstraints.KeyValuePair("OfferToReceiveVideo", isVideoCall ? "true" : "false")); createLocalStream(); } catch (Exception e) { Log.e(TAG, "Failed to initialize WebRTC", e); if (listener != null) listener.onCallFailed("Failed to initialize"); } } private void createLocalStream() { try { AudioSource audioSource = peerConnectionFactory.createAudioSource(new MediaConstraints()); localAudioTrack = peerConnectionFactory.createAudioTrack("audio0", audioSource); localAudioTrack.setEnabled(true); if (isVideoCall) { VideoCapturer videoCapturer = createVideoCapturer(); if (videoCapturer != null) { SurfaceTextureHelper surfaceHelper = SurfaceTextureHelper.create("CaptureThread", eglBase.getEglBaseContext()); videoSource = peerConnectionFactory.createVideoSource(videoCapturer.isScreencast()); videoCapturer.initialize(surfaceHelper, context, videoSource.getCapturerObserver()); videoCapturer.startCapture(1280, 720, 30); localVideoTrack = peerConnectionFactory.createVideoTrack("video0", videoSource); localVideoTrack.setEnabled(true); if (listener != null) listener.onLocalStream(localVideoTrack); } } } catch (Exception e) { Log.e(TAG, "Failed to create local stream", e); } } private VideoCapturer createVideoCapturer() { try { Camera2Enumerator enumerator = new Camera2Enumerator(context); String[] deviceNames = enumerator.getDeviceNames(); for (String name : deviceNames) { if (isFrontCamera && enumerator.isFrontFacing(name)) { VideoCapturer capturer = enumerator.createCapturer(name, null); if (capturer != null) return capturer; } } for (String name : deviceNames) { if (!isFrontCamera && enumerator.isBackFacing(name)) { VideoCapturer capturer = enumerator.createCapturer(name, null); if (capturer != null) return capturer; } } if (deviceNames.length > 0) { return enumerator.createCapturer(deviceNames[0], null); } } catch (Exception e) { Log.e(TAG, "Failed to create video capturer", e); } return null; } public void createPeerConnection() { try { PeerConnection.RTCConfiguration config = new PeerConnection.RTCConfiguration(iceServers); config.iceTransportsType = PeerConnection.IceTransportsType.ALL; config.bundlePolicy = PeerConnection.BundlePolicy.MAXBUNDLE; config.rtcpMuxPolicy = PeerConnection.RtcpMuxPolicy.REQUIRE; config.sdpSemantics = PeerConnection.SdpSemantics.UNIFIED_PLAN; peerConnection = peerConnectionFactory.createPeerConnection(config, new PeerConnection.Observer() { @Override public void onSignalingChange(PeerConnection.SignalingState state) {} @Override public void onIceConnectionChange(PeerConnection.IceConnectionState state) { Log.d(TAG, "ICE state: " + state); if (state == PeerConnection.IceConnectionState.CONNECTED) { if (listener != null) listener.onCallConnected(); } else if (state == PeerConnection.IceConnectionState.DISCONNECTED || state == PeerConnection.IceConnectionState.FAILED) { if (listener != null) listener.onCallDisconnected(); } } @Override public void onIceConnectionReceivingChange(boolean b) {} @Override public void onIceGatheringChange(PeerConnection.IceGatheringState state) {} @Override public void onIceCandidate(IceCandidate candidate) { if (listener != null) listener.onIceCandidateGenerated(candidate); sendIceCandidateToFirebase(candidate); } @Override public void onIceCandidatesRemoved(IceCandidate[] candidates) {} @Override public void onAddStream(MediaStream stream) {} @Override public void onRemoveStream(MediaStream stream) {} @Override public void onDataChannel(DataChannel channel) {} @Override public void onRenegotiationNeeded() {} @Override public void onAddTrack(RtpReceiver receiver, MediaStream[] streams) { try { if (receiver.track() instanceof VideoTrack) { VideoTrack remoteVideo = (VideoTrack) receiver.track(); if (listener != null) listener.onRemoteStream(remoteVideo); } } catch (Exception e) { Log.e(TAG, "onAddTrack error", e); } } }); if (peerConnection == null) { if (listener != null) listener.onCallFailed("Failed to create peer connection"); return; } if (localAudioTrack != null) { peerConnection.addTrack(localAudioTrack); } if (localVideoTrack != null) { peerConnection.addTrack(localVideoTrack); } for (IceCandidate candidate : pendingCandidates) { peerConnection.addIceCandidate(candidate); } pendingCandidates.clear(); } catch (Exception e) { Log.e(TAG, "createPeerConnection error", e); if (listener != null) listener.onCallFailed("Connection error"); } } public void createOffer(SdpCallback callback) { if (peerConnection == null) return; try { peerConnection.createOffer(new SdpObserver() { @Override public void onCreateSuccess(SessionDescription sdp) { peerConnection.setLocalDescription(new SdpObserver() { @Override public void onCreateSuccess(SessionDescription s) {} @Override public void onSetSuccess() { callback.onSdpCreated(sdp.description); } @Override public void onCreateFailure(String s) {} @Override public void onSetFailure(String s) {} }, sdp); } @Override public void onSetSuccess() {} @Override public void onCreateFailure(String s) { callback.onFailure(s); } @Override public void onSetFailure(String s) {} }, mediaConstraints); } catch (Exception e) { callback.onFailure(e.getMessage()); } } public void createAnswer(String offerSdp, SdpCallback callback) { if (peerConnection == null) return; try { SessionDescription offer = new SessionDescription(SessionDescription.Type.OFFER, offerSdp); peerConnection.setRemoteDescription(new SdpObserver() { @Override public void onCreateSuccess(SessionDescription s) {} @Override public void onSetSuccess() { peerConnection.createAnswer(new SdpObserver() { @Override public void onCreateSuccess(SessionDescription sdp) { peerConnection.setLocalDescription(new SdpObserver() { @Override public void onCreateSuccess(SessionDescription s) {} @Override public void onSetSuccess() { callback.onSdpCreated(sdp.description); } @Override public void onCreateFailure(String s) {} @Override public void onSetFailure(String s) {} }, sdp); } @Override public void onSetSuccess() {} @Override public void onCreateFailure(String s) { callback.onFailure(s); } @Override public void onSetFailure(String s) {} }, mediaConstraints); } @Override public void onCreateFailure(String s) {} @Override public void onSetFailure(String s) { callback.onFailure(s); } }, offer); } catch (Exception e) { callback.onFailure(e.getMessage()); } } public void setRemoteAnswer(String answerSdp) { if (peerConnection == null) return; try { SessionDescription answer = new SessionDescription(SessionDescription.Type.ANSWER, answerSdp); peerConnection.setRemoteDescription(new SdpObserver() { @Override public void onCreateSuccess(SessionDescription s) {} @Override public void onSetSuccess() { Log.d(TAG, "Remote description set"); } @Override public void onCreateFailure(String s) {} @Override public void onSetFailure(String s) { Log.e(TAG, "setRemoteAnswer failed: " + s); } }, answer); } catch (Exception e) { Log.e(TAG, "setRemoteAnswer error", e); } } public void addIceCandidate(IceCandidate candidate) { if (peerConnection != null) { peerConnection.addIceCandidate(candidate); } else { pendingCandidates.add(candidate); } } private void sendIceCandidateToFirebase(IceCandidate candidate) { if (callId == null) return; try { String uid = com.wechat.messenger.utils.ChatUtils.getCurrentUserId(); DatabaseReference ref = FirebaseManager.getInstance().getIceCandidatesRef(callId, uid); String key = ref.push().getKey(); if (key != null) { Map<String, String> data = new HashMap<>(); data.put("sdpMid", candidate.sdpMid); data.put("sdpMLineIndex", String.valueOf(candidate.sdpMLineIndex)); data.put("sdp", candidate.sdp); ref.child(key).setValue(data); } } catch (Exception e) { Log.e(TAG, "sendIceCandidateToFirebase error", e); } } public void toggleMute() { if (localAudioTrack != null) { isMuted = !isMuted; localAudioTrack.setEnabled(!isMuted); } } public void toggleCamera() { if (localVideoTrack != null) { isCameraOff = !isCameraOff; localVideoTrack.setEnabled(!isCameraOff); } } public boolean isMuted() { return isMuted; } public boolean isCameraOff() { return isCameraOff; } public void setCallId(String callId) { this.callId = callId; } public void setListener(WebRTCListener listener) { this.listener = listener; } public void release() { try { if (localVideoTrack != null) { localVideoTrack.dispose(); localVideoTrack = null; } if (localAudioTrack != null) { localAudioTrack.dispose(); localAudioTrack = null; } if (videoSource != null) { videoSource.dispose(); videoSource = null; } if (peerConnection != null) { peerConnection.close(); peerConnection.dispose(); peerConnection = null; } if (peerConnectionFactory != null) { peerConnectionFactory.dispose(); peerConnectionFactory = null; } } catch (Exception e) { Log.e(TAG, "release error", e); } } public interface SdpCallback { void onSdpCreated(String sdp); void onFailure(String error); } } EOF # ─── WORKERS ─────────────────────────────────────────────────────────────────── cat > app/src/main/java/$PACKAGE_PATH/workers/MessageSyncWorker.java <<'EOF' package com.wechat.messenger.workers; import android.content.Context; import androidx.annotation.NonNull; import androidx.work.*; import com.google.firebase.database.*; import com.wechat.messenger.database.WeChatDatabase; import com.wechat.messenger.database.entities.MessageEntity; import com.wechat.messenger.managers.FirebaseManager; import com.wechat.messenger.models.Message; import com.wechat.messenger.utils.NetworkUtils; import java.util.List; import java.util.concurrent.TimeUnit; public class MessageSyncWorker extends Worker { public static final String TAG = "MessageSyncWorker"; public MessageSyncWorker(@NonNull Context context, @NonNull WorkerParameters params) { super(context, params); } @NonNull @Override public Result doWork() { if (!NetworkUtils.isConnected(getApplicationContext())) { return Result.retry(); } try { WeChatDatabase db = WeChatDatabase.getInstance(getApplicationContext()); List<MessageEntity> unsyncedMessages = db.messageDao().getUnsyncedMessages(); for (MessageEntity entity : unsyncedMessages) { Message message = entityToModel(entity); DatabaseReference ref = FirebaseManager.getInstance() .getMessagesRef(entity.chatId).child(entity.messageId); ref.setValue(message); db.messageDao().markAsSynced(entity.messageId); } return Result.success(); } catch (Exception e) { return Result.retry(); } } private Message entityToModel(MessageEntity entity) { Message message = new Message(); message.setMessageId(entity.messageId); message.setChatId(entity.chatId); message.setSenderId(entity.senderId); message.setReceiverId(entity.receiverId); message.setType(entity.type); message.setContent(entity.content); message.setTimestamp(entity.timestamp); message.setStatus(entity.status); return message; } public static void scheduleSync(Context context) { Constraints constraints = new Constraints.Builder() .setRequiredNetworkType(NetworkType.CONNECTED) .build(); OneTimeWorkRequest request = new OneTimeWorkRequest.Builder(MessageSyncWorker.class) .setConstraints(constraints) .setBackoffCriteria(BackoffPolicy.EXPONENTIAL, 15, TimeUnit.SECONDS) .addTag(TAG) .build(); WorkManager.getInstance(context).enqueueUniqueWork(TAG, ExistingWorkPolicy.REPLACE, request); } } EOF # ─── SERVICES ────────────────────────────────────────────────────────────────── cat > app/src/main/java/$PACKAGE_PATH/services/WeChatFirebaseMessagingService.java <<'EOF' package com.wechat.messenger.services; import android.app.*; import android.content.Intent; import android.os.Build; import androidx.core.app.NotificationCompat; import androidx.core.app.NotificationManagerCompat; import com.google.firebase.messaging.FirebaseMessagingService; import com.google.firebase.messaging.RemoteMessage; import com.wechat.messenger.R; import com.wechat.messenger.WeChatApplication; import com.wechat.messenger.activities.*; import com.wechat.messenger.managers.FirebaseManager; import com.wechat.messenger.utils.*; public class WeChatFirebaseMessagingService extends FirebaseMessagingService { @Override public void onNewToken(String token) { super.onNewToken(token); try { PreferenceManager prefs = new PreferenceManager(this); String uid = prefs.getString(Constants.PREF_AUTH_UID); if (uid != null) { FirebaseManager.getInstance().updateFcmToken(uid, token); } } catch (Exception e) { e.printStackTrace(); } } @Override public void onMessageReceived(RemoteMessage remoteMessage) { super.onMessageReceived(remoteMessage); try { if (remoteMessage.getData().isEmpty()) return; String type = remoteMessage.getData().get("type"); if ("call".equals(type)) { handleCallNotification(remoteMessage); } else { handleMessageNotification(remoteMessage); } } catch (Exception e) { e.printStackTrace(); } } private void handleMessageNotification(RemoteMessage message) { String title = message.getData().get("senderName"); String body = message.getData().get("message"); String chatId = message.getData().get("chatId"); if (title == null) title = "New Message"; if (body == null) body = ""; Intent intent = new Intent(this, ChatActivity.class); intent.putExtra(Constants.EXTRA_CHAT_ID, chatId); intent.addFlags(Intent.FLAG_ACTIVITY_CLEAR_TOP); PendingIntent pendingIntent = PendingIntent.getActivity(this, 0, intent, PendingIntent.FLAG_UPDATE_CURRENT | PendingIntent.FLAG_IMMUTABLE); NotificationCompat.Builder builder = new NotificationCompat.Builder(this, WeChatApplication.CHANNEL_MESSAGES) .setSmallIcon(R.drawable.ic_notification) .setContentTitle(title) .setContentText(body) .setAutoCancel(true) .setPriority(NotificationCompat.PRIORITY_HIGH) .setContentIntent(pendingIntent); NotificationManagerCompat.from(this).notify((int) System.currentTimeMillis(), builder.build()); } private void handleCallNotification(RemoteMessage message) { String callId = message.getData().get("callId"); String callerName = message.getData().get("callerName"); String callType = message.getData().get("callType"); Intent fullScreenIntent = new Intent(this, IncomingCallActivity.class); fullScreenIntent.putExtra(Constants.EXTRA_CALL_ID, callId); fullScreenIntent.putExtra("callerName", callerName); fullScreenIntent.putExtra("callType", callType); fullScreenIntent.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK); PendingIntent fullScreenPending = PendingIntent.getActivity(this, 1, fullScreenIntent, PendingIntent.FLAG_UPDATE_CURRENT | PendingIntent.FLAG_IMMUTABLE); NotificationCompat.Builder builder = new NotificationCompat.Builder(this, WeChatApplication.CHANNEL_CALLS) .setSmallIcon(R.drawable.ic_call) .setContentTitle("Incoming " + (callType != null ? callType : "Voice") + " Call") .setContentText(callerName != null ? callerName : "Unknown") .setAutoCancel(false) .setPriority(NotificationCompat.PRIORITY_MAX) .setCategory(NotificationCompat.CATEGORY_CALL) .setFullScreenIntent(fullScreenPending, true); NotificationManagerCompat.from(this).notify(999, builder.build()); } } EOF cat > app/src/main/java/$PACKAGE_PATH/services/CallService.java <<'EOF' package com.wechat.messenger.services; import android.app.*; import android.content.Intent; import android.os.*; import androidx.core.app.NotificationCompat; import com.wechat.messenger.R; import com.wechat.messenger.WeChatApplication; import com.wechat.messenger.activities.CallActivity; public class CallService extends Service { private static final int NOTIFICATION_ID = 1001; private IBinder binder = new LocalBinder(); public class LocalBinder extends Binder { public CallService getService() { return CallService.this; } } @Override public IBinder onBind(Intent intent) { return binder; } @Override public int onStartCommand(Intent intent, int flags, int startId) { startForeground(NOTIFICATION_ID, buildNotification()); return START_STICKY; } private Notification buildNotification() { Intent intent = new Intent(this, CallActivity.class); intent.addFlags(Intent.FLAG_ACTIVITY_SINGLE_TOP); PendingIntent pi = PendingIntent.getActivity(this, 0, intent, PendingIntent.FLAG_UPDATE_CURRENT | PendingIntent.FLAG_IMMUTABLE); return new NotificationCompat.Builder(this, WeChatApplication.CHANNEL_CALLS) .setSmallIcon(R.drawable.ic_call) .setContentTitle("WeChat Call") .setContentText("Call in progress") .setContentIntent(pi) .setOngoing(true) .build(); } @Override public void onDestroy() { super.onDestroy(); stopForeground(true); } } EOF # ─── RECEIVERS ───────────────────────────────────────────────────────────────── cat > app/src/main/java/$PACKAGE_PATH/receivers/NotificationActionReceiver.java <<'EOF' package com.wechat.messenger.receivers; import android.content.*; import com.wechat.messenger.utils.Constants; public class NotificationActionReceiver extends BroadcastReceiver { @Override public void onReceive(Context context, Intent intent) { String action = intent.getAction(); if (action == null) return; switch (action) { case Constants.ACTION_ACCEPT_CALL: break; case Constants.ACTION_REJECT_CALL: break; case Constants.ACTION_MARK_READ: break; } } } EOF cat > app/src/main/java/$PACKAGE_PATH/receivers/BootReceiver.java <<'EOF' package com.wechat.messenger.receivers; import android.content.*; import com.wechat.messenger.workers.MessageSyncWorker; public class BootReceiver extends BroadcastReceiver { @Override public void onReceive(Context context, Intent intent) { if (Intent.ACTION_BOOT_COMPLETED.equals(intent.getAction())) { MessageSyncWorker.scheduleSync(context); } } } EOF # ─── ADAPTERS ────────────────────────────────────────────────────────────────── cat > app/src/main/java/$PACKAGE_PATH/adapters/MessageAdapter.java <<'EOF' package com.wechat.messenger.adapters; import android.content.Context; import android.view.*; import android.widget.*; import androidx.annotation.NonNull; import androidx.recyclerview.widget.RecyclerView; import com.wechat.messenger.R; import com.wechat.messenger.database.entities.MessageEntity; import com.wechat.messenger.utils.*; import java.util.*; public class MessageAdapter extends RecyclerView.Adapter<RecyclerView.ViewHolder> { private static final int VIEW_TYPE_SENT = 1; private static final int VIEW_TYPE_RECEIVED = 2; private static final int VIEW_TYPE_SENT_IMAGE = 3; private static final int VIEW_TYPE_RECEIVED_IMAGE = 4; private Context context; private List<MessageEntity> messages = new ArrayList<>(); private String currentUserId; private MessageClickListener listener; public interface MessageClickListener { void onMessageLongClick(MessageEntity message, View view); void onReplySwipe(MessageEntity message); void onImageClick(MessageEntity message); } public MessageAdapter(Context context, String currentUserId, MessageClickListener listener) { this.context = context; this.currentUserId = currentUserId; this.listener = listener; setHasStableIds(true); } @Override public long getItemId(int position) { if (position < 0 || position >= messages.size()) return RecyclerView.NO_ID; return messages.get(position).messageId.hashCode(); } @Override public int getItemViewType(int position) { MessageEntity message = messages.get(position); boolean isSent = currentUserId != null && currentUserId.equals(message.senderId); if ("IMAGE".equals(message.type)) { return isSent ? VIEW_TYPE_SENT_IMAGE : VIEW_TYPE_RECEIVED_IMAGE; } return isSent ? VIEW_TYPE_SENT : VIEW_TYPE_RECEIVED; } @NonNull @Override public RecyclerView.ViewHolder onCreateViewHolder(@NonNull ViewGroup parent, int viewType) { LayoutInflater inflater = LayoutInflater.from(context); switch (viewType) { case VIEW_TYPE_SENT: return new SentMessageViewHolder(inflater.inflate(R.layout.item_message_sent, parent, false)); case VIEW_TYPE_RECEIVED: return new ReceivedMessageViewHolder(inflater.inflate(R.layout.item_message_received, parent, false)); case VIEW_TYPE_SENT_IMAGE: return new SentImageViewHolder(inflater.inflate(R.layout.item_message_sent_image, parent, false)); case VIEW_TYPE_RECEIVED_IMAGE: return new ReceivedImageViewHolder(inflater.inflate(R.layout.item_message_received_image, parent, false)); default: return new SentMessageViewHolder(inflater.inflate(R.layout.item_message_sent, parent, false)); } } @Override public void onBindViewHolder(@NonNull RecyclerView.ViewHolder holder, int position) { MessageEntity message = messages.get(position); AnimationUtils.animateMessageAppear(holder.itemView); if (holder instanceof SentMessageViewHolder) { ((SentMessageViewHolder) holder).bind(message); } else if (holder instanceof ReceivedMessageViewHolder) { ((ReceivedMessageViewHolder) holder).bind(message); } else if (holder instanceof SentImageViewHolder) { ((SentImageViewHolder) holder).bind(message); } else if (holder instanceof ReceivedImageViewHolder) { ((ReceivedImageViewHolder) holder).bind(message); } } @Override public int getItemCount() { return messages.size(); } public void setMessages(List<MessageEntity> newMessages) { this.messages = new ArrayList<>(newMessages); notifyDataSetChanged(); } public void addMessage(MessageEntity message) { messages.add(message); notifyItemInserted(messages.size() - 1); } public void updateMessage(MessageEntity message) { for (int i = 0; i < messages.size(); i++) { if (messages.get(i).messageId.equals(message.messageId)) { messages.set(i, message); notifyItemChanged(i); break; } } } private String getStatusText(int status) { switch (status) { case 1: return "✓"; case 2: return "✓✓"; case 3: return "✓✓"; default: return "⏳"; } } class SentMessageViewHolder extends RecyclerView.ViewHolder { TextView tvMessage, tvTime, tvStatus, tvEdited; LinearLayout replyContainer; TextView tvReplyContent; SentMessageViewHolder(View itemView) { super(itemView); tvMessage = itemView.findViewById(R.id.tvMessage); tvTime = itemView.findViewById(R.id.tvTime); tvStatus = itemView.findViewById(R.id.tvStatus); tvEdited = itemView.findViewById(R.id.tvEdited); replyContainer = itemView.findViewById(R.id.replyContainer); tvReplyContent = itemView.findViewById(R.id.tvReplyContent); } void bind(MessageEntity message) { if (message.isDeleted) { tvMessage.setText("This message was deleted"); tvMessage.setAlpha(0.6f); } else { tvMessage.setText(message.content != null ? message.content : ""); tvMessage.setAlpha(1f); } tvTime.setText(DateUtils.formatMessageTime(message.timestamp)); if (tvStatus != null) { tvStatus.setText(getStatusText(message.status)); tvStatus.setTextColor(message.status == 3 ? context.getResources().getColor(R.color.read_tick, null) : context.getResources().getColor(R.color.sent_tick, null)); } if (tvEdited != null) { tvEdited.setVisibility(message.isEdited ? View.VISIBLE : View.GONE); } if (replyContainer != null) { if (message.replyToMessageId != null && !message.replyToMessageId.isEmpty()) { replyContainer.setVisibility(View.VISIBLE); if (tvReplyContent != null) tvReplyContent.setText(message.replyToContent); } else { replyContainer.setVisibility(View.GONE); } } itemView.setOnLongClickListener(v -> { if (listener != null) listener.onMessageLongClick(message, v); return true; }); } } class ReceivedMessageViewHolder extends RecyclerView.ViewHolder { TextView tvMessage, tvTime; LinearLayout replyContainer; TextView tvReplyContent; ReceivedMessageViewHolder(View itemView) { super(itemView); tvMessage = itemView.findViewById(R.id.tvMessage); tvTime = itemView.findViewById(R.id.tvTime); replyContainer = itemView.findViewById(R.id.replyContainer); tvReplyContent = itemView.findViewById(R.id.tvReplyContent); } void bind(MessageEntity message) { if (message.isDeleted) { tvMessage.setText("This message was deleted"); tvMessage.setAlpha(0.6f); } else { tvMessage.setText(message.content != null ? message.content : ""); tvMessage.setAlpha(1f); } tvTime.setText(DateUtils.formatMessageTime(message.timestamp)); if (replyContainer != null) { if (message.replyToMessageId != null && !message.replyToMessageId.isEmpty()) { replyContainer.setVisibility(View.VISIBLE); if (tvReplyContent != null) tvReplyContent.setText(message.replyToContent); } else { replyContainer.setVisibility(View.GONE); } } itemView.setOnLongClickListener(v -> { if (listener != null) listener.onMessageLongClick(message, v); return true; }); } } class SentImageViewHolder extends RecyclerView.ViewHolder { ImageView ivImage; TextView tvTime, tvStatus; SentImageViewHolder(View itemView) { super(itemView); ivImage = itemView.findViewById(R.id.ivImage); tvTime = itemView.findViewById(R.id.tvTime); tvStatus = itemView.findViewById(R.id.tvStatus); } void bind(MessageEntity message) { if (ivImage != null && message.thumbnailBase64 != null) { ImageUtils.loadBase64ImageRaw(context, message.thumbnailBase64, ivImage); } if (tvTime != null) tvTime.setText(DateUtils.formatMessageTime(message.timestamp)); if (tvStatus != null) tvStatus.setText(getStatusText(message.status)); if (ivImage != null) { ivImage.setOnClickListener(v -> { if (listener != null) listener.onImageClick(message); }); } itemView.setOnLongClickListener(v -> { if (listener != null) listener.onMessageLongClick(message, v); return true; }); } } class ReceivedImageViewHolder extends RecyclerView.ViewHolder { ImageView ivImage; TextView tvTime; ReceivedImageViewHolder(View itemView) { super(itemView); ivImage = itemView.findViewById(R.id.ivImage); tvTime = itemView.findViewById(R.id.tvTime); } void bind(MessageEntity message) { if (ivImage != null && message.thumbnailBase64 != null) { ImageUtils.loadBase64ImageRaw(context, message.thumbnailBase64, ivImage); } if (tvTime != null) tvTime.setText(DateUtils.formatMessageTime(message.timestamp)); if (ivImage != null) { ivImage.setOnClickListener(v -> { if (listener != null) listener.onImageClick(message); }); } itemView.setOnLongClickListener(v -> { if (listener != null) listener.onMessageLongClick(message, v); return true; }); } } } EOF cat > app/src/main/java/$PACKAGE_PATH/adapters/ChatListAdapter.java <<'EOF' package com.wechat.messenger.adapters; import android.content.Context; import android.view.*; import android.widget.*; import androidx.annotation.NonNull; import androidx.recyclerview.widget.RecyclerView; import com.wechat.messenger.R; import com.wechat.messenger.database.entities.ChatEntity; import com.wechat.messenger.utils.*; import de.hdodenhof.circleimageview.CircleImageView; import java.util.*; public class ChatListAdapter extends RecyclerView.Adapter<ChatListAdapter.ChatViewHolder> { private Context context; private List<ChatEntity> chats = new ArrayList<>(); private ChatClickListener listener; public interface ChatClickListener { void onChatClick(ChatEntity chat); void onChatLongClick(ChatEntity chat); } public ChatListAdapter(Context context, ChatClickListener listener) { this.context = context; this.listener = listener; setHasStableIds(true); } @Override public long getItemId(int position) { return chats.get(position).chatId.hashCode(); } @NonNull @Override public ChatViewHolder onCreateViewHolder(@NonNull ViewGroup parent, int viewType) { View view = LayoutInflater.from(context).inflate(R.layout.item_chat, parent, false); return new ChatViewHolder(view); } @Override public void onBindViewHolder(@NonNull ChatViewHolder holder, int position) { holder.bind(chats.get(position)); } @Override public int getItemCount() { return chats.size(); } public void setChats(List<ChatEntity> newChats) { this.chats = new ArrayList<>(newChats); notifyDataSetChanged(); } public void filterChats(String query, List<ChatEntity> allChats) { if (query.isEmpty()) { setChats(allChats); return; } List<ChatEntity> filtered = new ArrayList<>(); for (ChatEntity chat : allChats) { if (chat.otherUserName != null && chat.otherUserName.toLowerCase().contains(query.toLowerCase())) { filtered.add(chat); } } setChats(filtered); } class ChatViewHolder extends RecyclerView.ViewHolder { CircleImageView ivAvatar; TextView tvName, tvLastMessage, tvTime, tvUnread; View onlineIndicator; TextView tvTyping; ImageView ivMessageStatus; ChatViewHolder(View itemView) { super(itemView); ivAvatar = itemView.findViewById(R.id.ivAvatar); tvName = itemView.findViewById(R.id.tvName); tvLastMessage = itemView.findViewById(R.id.tvLastMessage); tvTime = itemView.findViewById(R.id.tvTime); tvUnread = itemView.findViewById(R.id.tvUnread); onlineIndicator = itemView.findViewById(R.id.onlineIndicator); tvTyping = itemView.findViewById(R.id.tvTyping); } void bind(ChatEntity chat) { if (tvName != null) tvName.setText(chat.otherUserName != null ? chat.otherUserName : "Unknown"); if (chat.isTyping) { if (tvTyping != null) tvTyping.setVisibility(View.VISIBLE); if (tvLastMessage != null) tvLastMessage.setVisibility(View.GONE); } else { if (tvTyping != null) tvTyping.setVisibility(View.GONE); if (tvLastMessage != null) { tvLastMessage.setVisibility(View.VISIBLE); String last = chat.lastMessage; if ("IMAGE".equals(chat.lastMessageType)) last = "📷 Photo"; else if ("VOICE".equals(chat.lastMessageType)) last = "🎵 Voice message"; tvLastMessage.setText(last != null ? last : ""); } } if (tvTime != null && chat.lastMessageTime > 0) { tvTime.setText(DateUtils.formatChatListTime(chat.lastMessageTime)); } if (tvUnread != null) { if (chat.unreadCount > 0) { tvUnread.setVisibility(View.VISIBLE); tvUnread.setText(chat.unreadCount > 99 ? "99+" : String.valueOf(chat.unreadCount)); AnimationUtils.animateBadgeBounce(tvUnread); } else { tvUnread.setVisibility(View.GONE); } } if (onlineIndicator != null) { onlineIndicator.setVisibility(chat.isOnline ? View.VISIBLE : View.GONE); } if (ivAvatar != null) { ImageUtils.loadBase64Image(context, chat.otherUserImage, ivAvatar, R.drawable.ic_default_avatar); } itemView.setOnClickListener(v -> { if (listener != null) listener.onChatClick(chat); }); itemView.setOnLongClickListener(v -> { if (listener != null) listener.onChatLongClick(chat); return true; }); } } } EOF cat > app/src/main/java/$PACKAGE_PATH/adapters/ContactAdapter.java <<'EOF' package com.wechat.messenger.adapters; import android.content.Context; import android.view.*; import android.widget.*; import androidx.annotation.NonNull; import androidx.recyclerview.widget.RecyclerView; import com.wechat.messenger.R; import com.wechat.messenger.database.entities.ContactEntity; import com.wechat.messenger.utils.ImageUtils; import de.hdodenhof.circleimageview.CircleImageView; import java.util.*; public class ContactAdapter extends RecyclerView.Adapter<ContactAdapter.ContactViewHolder> { private Context context; private List<ContactEntity> contacts = new ArrayList<>(); private ContactClickListener listener; public interface ContactClickListener { void onContactClick(ContactEntity contact); void onVideoCallClick(ContactEntity contact); void onVoiceCallClick(ContactEntity contact); } public ContactAdapter(Context context, ContactClickListener listener) { this.context = context; this.listener = listener; } @NonNull @Override public ContactViewHolder onCreateViewHolder(@NonNull ViewGroup parent, int viewType) { return new ContactViewHolder(LayoutInflater.from(context).inflate(R.layout.item_contact, parent, false)); } @Override public void onBindViewHolder(@NonNull ContactViewHolder holder, int position) { holder.bind(contacts.get(position)); } @Override public int getItemCount() { return contacts.size(); } public void setContacts(List<ContactEntity> contacts) { this.contacts = new ArrayList<>(contacts); notifyDataSetChanged(); } class ContactViewHolder extends RecyclerView.ViewHolder { CircleImageView ivAvatar; TextView tvName, tvStatus; View onlineIndicator; ImageView btnCall, btnVideo; ContactViewHolder(View itemView) { super(itemView); ivAvatar = itemView.findViewById(R.id.ivAvatar); tvName = itemView.findViewById(R.id.tvName); tvStatus = itemView.findViewById(R.id.tvStatus); onlineIndicator = itemView.findViewById(R.id.onlineIndicator); btnCall = itemView.findViewById(R.id.btnCall); btnVideo = itemView.findViewById(R.id.btnVideo); } void bind(ContactEntity contact) { if (tvName != null) tvName.setText(contact.name); if (tvStatus != null) { tvStatus.setText(contact.isOnline ? "Online" : "Offline"); tvStatus.setTextColor(context.getResources().getColor( contact.isOnline ? R.color.online_green : R.color.text_secondary, null)); } if (onlineIndicator != null) onlineIndicator.setVisibility(contact.isOnline ? View.VISIBLE : View.GONE); if (ivAvatar != null) ImageUtils.loadBase64Image(context, contact.profileImageBase64, ivAvatar, R.drawable.ic_default_avatar); itemView.setOnClickListener(v -> { if (listener != null) listener.onContactClick(contact); }); if (btnCall != null) btnCall.setOnClickListener(v -> { if (listener != null) listener.onVoiceCallClick(contact); }); if (btnVideo != null) btnVideo.setOnClickListener(v -> { if (listener != null) listener.onVideoCallClick(contact); }); } } } EOF cat > app/src/main/java/$PACKAGE_PATH/adapters/FriendRequestAdapter.java <<'EOF' package com.wechat.messenger.adapters; import android.content.Context; import android.view.*; import android.widget.*; import androidx.annotation.NonNull; import androidx.recyclerview.widget.RecyclerView; import com.wechat.messenger.R; import com.wechat.messenger.models.FriendRequest; import com.wechat.messenger.utils.ImageUtils; import de.hdodenhof.circleimageview.CircleImageView; import java.util.*; public class FriendRequestAdapter extends RecyclerView.Adapter<FriendRequestAdapter.ViewHolder> { private Context context; private List<FriendRequest> requests = new ArrayList<>(); private RequestActionListener listener; public interface RequestActionListener { void onAccept(FriendRequest request); void onReject(FriendRequest request); } public FriendRequestAdapter(Context context, RequestActionListener listener) { this.context = context; this.listener = listener; } @NonNull @Override public ViewHolder onCreateViewHolder(@NonNull ViewGroup parent, int viewType) { return new ViewHolder(LayoutInflater.from(context).inflate(R.layout.item_friend_request, parent, false)); } @Override public void onBindViewHolder(@NonNull ViewHolder holder, int position) { holder.bind(requests.get(position)); } @Override public int getItemCount() { return requests.size(); } public void setRequests(List<FriendRequest> requests) { this.requests = new ArrayList<>(requests); notifyDataSetChanged(); } class ViewHolder extends RecyclerView.ViewHolder { CircleImageView ivAvatar; TextView tvName; Button btnAccept, btnReject; ViewHolder(View itemView) { super(itemView); ivAvatar = itemView.findViewById(R.id.ivAvatar); tvName = itemView.findViewById(R.id.tvName); btnAccept = itemView.findViewById(R.id.btnAccept); btnReject = itemView.findViewById(R.id.btnReject); } void bind(FriendRequest request) { if (tvName != null) tvName.setText(request.getFromName()); if (ivAvatar != null) ImageUtils.loadBase64Image(context, request.getFromImage(), ivAvatar, R.drawable.ic_default_avatar); if (btnAccept != null) btnAccept.setOnClickListener(v -> { if (listener != null) listener.onAccept(request); }); if (btnReject != null) btnReject.setOnClickListener(v -> { if (listener != null) listener.onReject(request); }); } } } EOF # ─── ACTIVITIES ──────────────────────────────────────────────────────────────── cat > app/src/main/java/$PACKAGE_PATH/activities/SplashActivity.java <<'EOF' package com.wechat.messenger.activities; import android.content.Intent; import android.os.Bundle; import android.os.Handler; import android.os.Looper; import androidx.appcompat.app.AppCompatActivity; import com.google.firebase.auth.FirebaseAuth; import com.wechat.messenger.R; import com.wechat.messenger.utils.PreferenceManager; public class SplashActivity extends AppCompatActivity { @Override protected void onCreate(Bundle savedInstanceState) { super.onCreate(savedInstanceState); setContentView(R.layout.activity_splash); new Handler(Looper.getMainLooper()).postDelayed(this::checkAuth, 2000); } private void checkAuth() { try { PreferenceManager prefs = new PreferenceManager(this); if (FirebaseAuth.getInstance().getCurrentUser() != null && FirebaseAuth.getInstance().getCurrentUser().isEmailVerified() && prefs.isLoggedIn()) { startActivity(new Intent(this, MainActivity.class)); } else { startActivity(new Intent(this, LoginActivity.class)); } finish(); } catch (Exception e) { startActivity(new Intent(this, LoginActivity.class)); finish(); } } } EOF cat > app/src/main/java/$PACKAGE_PATH/activities/LoginActivity.java <<'EOF' package com.wechat.messenger.activities; import android.content.Intent; import android.os.Bundle; import android.view.View; import android.widget.*; import androidx.appcompat.app.AppCompatActivity; import com.google.android.material.textfield.TextInputEditText; import com.google.firebase.auth.*; import com.google.firebase.database.*; import com.wechat.messenger.R; import com.wechat.messenger.models.User; import com.wechat.messenger.utils.*; public class LoginActivity extends AppCompatActivity { private TextInputEditText etEmail, etPassword; private Button btnLogin; private TextView tvRegister, tvForgotPassword; private ProgressBar progressBar; private FirebaseAuth auth; private PreferenceManager prefs; @Override protected void onCreate(Bundle savedInstanceState) { super.onCreate(savedInstanceState); setContentView(R.layout.activity_login); auth = FirebaseAuth.getInstance(); prefs = new PreferenceManager(this); initViews(); setupClickListeners(); } private void initViews() { etEmail = findViewById(R.id.etEmail); etPassword = findViewById(R.id.etPassword); btnLogin = findViewById(R.id.btnLogin); tvRegister = findViewById(R.id.tvRegister); tvForgotPassword = findViewById(R.id.tvForgotPassword); progressBar = findViewById(R.id.progressBar); } private void setupClickListeners() { btnLogin.setOnClickListener(v -> attemptLogin()); tvRegister.setOnClickListener(v -> { startActivity(new Intent(this, RegisterActivity.class)); }); tvForgotPassword.setOnClickListener(v -> showForgotPasswordDialog()); } private void attemptLogin() { String email = etEmail.getText() != null ? etEmail.getText().toString().trim() : ""; String password = etPassword.getText() != null ? etPassword.getText().toString().trim() : ""; if (email.isEmpty()) { etEmail.setError("Email required"); return; } if (password.isEmpty()) { etPassword.setError("Password required"); return; } if (password.length() < 6) { etPassword.setError("Min 6 characters"); return; } setLoading(true); auth.signInWithEmailAndPassword(email, password) .addOnSuccessListener(result -> { FirebaseUser user = result.getUser(); if (user == null) { setLoading(false); showError("Login failed"); return; } if (!user.isEmailVerified()) { setLoading(false); showError("Please verify your email first"); user.sendEmailVerification(); auth.signOut(); return; } loadUserData(user.getUid()); }) .addOnFailureListener(e -> { setLoading(false); showError("Login failed: " + e.getMessage()); }); } private void loadUserData(String uid) { FirebaseDatabase.getInstance().getReference(Constants.USERS_REF).child(uid) .addListenerForSingleValueEvent(new ValueEventListener() { @Override public void onDataChange(DataSnapshot snapshot) { setLoading(false); User user = snapshot.getValue(User.class); if (user != null) { prefs.putString(Constants.PREF_AUTH_UID, uid); prefs.putString(Constants.PREF_USER_ID, user.getUserId()); prefs.putString(Constants.PREF_USER_NAME, user.getName()); startActivity(new Intent(LoginActivity.this, MainActivity.class)); finish(); } else { showError("User data not found"); } } @Override public void onCancelled(DatabaseError error) { setLoading(false); showError("Failed to load user data"); } }); } private void showForgotPasswordDialog() { String email = etEmail.getText() != null ? etEmail.getText().toString().trim() : ""; if (email.isEmpty()) { etEmail.setError("Enter email first"); return; } auth.sendPasswordResetEmail(email) .addOnSuccessListener(v -> Toast.makeText(this, "Reset email sent", Toast.LENGTH_SHORT).show()) .addOnFailureListener(e -> showError("Failed to send reset email")); } private void setLoading(boolean loading) { progressBar.setVisibility(loading ? View.VISIBLE : View.GONE); btnLogin.setEnabled(!loading); } private void showError(String msg) { Toast.makeText(this, msg, Toast.LENGTH_LONG).show(); } } EOF cat > app/src/main/java/$PACKAGE_PATH/activities/RegisterActivity.java <<'EOF' package com.wechat.messenger.activities; import android.content.Intent; import android.os.Bundle; import android.view.View; import android.widget.*; import androidx.appcompat.app.AppCompatActivity; import com.google.android.material.textfield.TextInputEditText; import com.google.firebase.auth.*; import com.google.firebase.database.*; import com.wechat.messenger.R; import com.wechat.messenger.managers.FirebaseManager; import com.wechat.messenger.models.User; import com.wechat.messenger.utils.*; public class RegisterActivity extends AppCompatActivity { private TextInputEditText etName, etEmail, etPassword, etConfirmPassword; private Button btnRegister; private TextView tvLogin; private ProgressBar progressBar; private FirebaseAuth auth; @Override protected void onCreate(Bundle savedInstanceState) { super.onCreate(savedInstanceState); setContentView(R.layout.activity_register); auth = FirebaseAuth.getInstance(); initViews(); setupClickListeners(); } private void initViews() { etName = findViewById(R.id.etName); etEmail = findViewById(R.id.etEmail); etPassword = findViewById(R.id.etPassword); etConfirmPassword = findViewById(R.id.etConfirmPassword); btnRegister = findViewById(R.id.btnRegister); tvLogin = findViewById(R.id.tvLogin); progressBar = findViewById(R.id.progressBar); } private void setupClickListeners() { btnRegister.setOnClickListener(v -> attemptRegister()); tvLogin.setOnClickListener(v -> finish()); } private void attemptRegister() { String name = etName.getText() != null ? etName.getText().toString().trim() : ""; String email = etEmail.getText() != null ? etEmail.getText().toString().trim() : ""; String password = etPassword.getText() != null ? etPassword.getText().toString().trim() : ""; String confirm = etConfirmPassword.getText() != null ? etConfirmPassword.getText().toString().trim() : ""; if (name.isEmpty()) { etName.setError("Name required"); return; } if (email.isEmpty()) { etEmail.setError("Email required"); return; } if (password.isEmpty()) { etPassword.setError("Password required"); return; } if (password.length() < 6) { etPassword.setError("Min 6 characters"); return; } if (!password.equals(confirm)) { etConfirmPassword.setError("Passwords don't match"); return; } setLoading(true); auth.createUserWithEmailAndPassword(email, password) .addOnSuccessListener(result -> { FirebaseUser fbUser = result.getUser(); if (fbUser == null) { setLoading(false); showError("Registration failed"); return; } fbUser.sendEmailVerification(); generateAndSaveUser(fbUser.getUid(), name, email); }) .addOnFailureListener(e -> { setLoading(false); showError("Registration failed: " + e.getMessage()); }); } private void generateAndSaveUser(String uid, String name, String email) { FirebaseManager.getInstance().generateUniqueUserId(userId -> { User user = new User(uid, userId, name, email); DatabaseReference userRef = FirebaseManager.getInstance().getUserRef(uid); DatabaseReference userIdsRef = FirebaseManager.getInstance().getUserIdsRef(); userRef.setValue(user) .addOnSuccessListener(v -> { userIdsRef.child(userId).setValue(uid); setLoading(false); auth.signOut(); Toast.makeText(this, "Registration successful! Please verify your email.", Toast.LENGTH_LONG).show(); startActivity(new Intent(this, LoginActivity.class)); finish(); }) .addOnFailureListener(e -> { setLoading(false); showError("Failed to save user data"); try { auth.getCurrentUser().delete(); } catch (Exception ex) {} }); }); } private void setLoading(boolean loading) { progressBar.setVisibility(loading ? View.VISIBLE : View.GONE); btnRegister.setEnabled(!loading); } private void showError(String msg) { Toast.makeText(this, msg, Toast.LENGTH_LONG).show(); } } EOF cat > app/src/main/java/$PACKAGE_PATH/activities/MainActivity.java <<'EOF' package com.wechat.messenger.activities; import android.content.Intent; import android.os.Bundle; import android.view.*; import android.widget.*; import androidx.appcompat.app.AppCompatActivity; import androidx.appcompat.widget.SearchView; import androidx.appcompat.widget.Toolbar; import androidx.lifecycle.*; import androidx.recyclerview.widget.LinearLayoutManager; import androidx.recyclerview.widget.RecyclerView; import com.google.android.material.bottomnavigation.BottomNavigationView; import com.google.android.material.floatingactionbutton.FloatingActionButton; import com.google.firebase.auth.FirebaseAuth; import com.google.firebase.database.*; import com.google.firebase.messaging.FirebaseMessaging; import com.wechat.messenger.R; import com.wechat.messenger.adapters.*; import com.wechat.messenger.database.WeChatDatabase; import com.wechat.messenger.database.entities.*; import com.wechat.messenger.managers.FirebaseManager; import com.wechat.messenger.models.Chat; import com.wechat.messenger.utils.*; import java.util.*; public class MainActivity extends AppCompatActivity { private RecyclerView rvChats, rvContacts; private ChatListAdapter chatListAdapter; private ContactAdapter contactAdapter; private BottomNavigationView bottomNav; private FloatingActionButton fabNewChat; private Toolbar toolbar; private PreferenceManager prefs; private WeChatDatabase db; private String currentUid; private ValueEventListener chatListener; private List<ChatEntity> allChats = new ArrayList<>(); @Override protected void onCreate(Bundle savedInstanceState) { super.onCreate(savedInstanceState); setContentView(R.layout.activity_main); prefs = new PreferenceManager(this); db = WeChatDatabase.getInstance(this); currentUid = prefs.getString(Constants.PREF_AUTH_UID); if (currentUid == null) { redirectToLogin(); return; } initViews(); setupRecyclerViews(); setupBottomNav(); setupFab(); setupToolbar(); updateFcmToken(); setUserOnline(true); loadChats(); loadContacts(); listenForFriendRequests(); } private void initViews() { toolbar = findViewById(R.id.toolbar); rvChats = findViewById(R.id.rvChats); rvContacts = findViewById(R.id.rvContacts); bottomNav = findViewById(R.id.bottomNav); fabNewChat = findViewById(R.id.fabNewChat); } private void setupToolbar() { if (toolbar != null) { setSupportActionBar(toolbar); if (getSupportActionBar() != null) getSupportActionBar().setTitle("WeChat"); } } private void setupRecyclerViews() { chatListAdapter = new ChatListAdapter(this, new ChatListAdapter.ChatClickListener() { @Override public void onChatClick(ChatEntity chat) { openChat(chat); } @Override public void onChatLongClick(ChatEntity chat) { showChatOptions(chat); } }); if (rvChats != null) { rvChats.setLayoutManager(new LinearLayoutManager(this)); rvChats.setAdapter(chatListAdapter); rvChats.setHasFixedSize(false); } contactAdapter = new ContactAdapter(this, new ContactAdapter.ContactClickListener() { @Override public void onContactClick(ContactEntity contact) { openChatWithContact(contact); } @Override public void onVideoCallClick(ContactEntity contact) { startVideoCall(contact); } @Override public void onVoiceCallClick(ContactEntity contact) { startVoiceCall(contact); } }); if (rvContacts != null) { rvContacts.setLayoutManager(new LinearLayoutManager(this)); rvContacts.setAdapter(contactAdapter); rvContacts.setVisibility(View.GONE); } } private void setupBottomNav() { if (bottomNav == null) return; bottomNav.setOnItemSelectedListener(item -> { int id = item.getItemId(); if (id == R.id.nav_chats) { if (rvChats != null) rvChats.setVisibility(View.VISIBLE); if (rvContacts != null) rvContacts.setVisibility(View.GONE); if (fabNewChat != null) fabNewChat.show(); return true; } else if (id == R.id.nav_contacts) { if (rvChats != null) rvChats.setVisibility(View.GONE); if (rvContacts != null) rvContacts.setVisibility(View.VISIBLE); if (fabNewChat != null) fabNewChat.hide(); return true; } else if (id == R.id.nav_profile) { startActivity(new Intent(this, ProfileActivity.class)); return true; } else if (id == R.id.nav_settings) { startActivity(new Intent(this, SettingsActivity.class)); return true; } return false; }); } private void setupFab() { if (fabNewChat != null) { fabNewChat.setOnClickListener(v -> showAddFriendDialog()); } } private void showAddFriendDialog() { android.app.AlertDialog.Builder builder = new android.app.AlertDialog.Builder(this); builder.setTitle("Add Friend"); View dialogView = LayoutInflater.from(this).inflate(R.layout.dialog_add_friend, null); builder.setView(dialogView); EditText etFriendId = dialogView.findViewById(R.id.etFriendId); builder.setPositiveButton("Send Request", (d, which) -> { String friendId = etFriendId.getText() != null ? etFriendId.getText().toString().trim() : ""; if (!friendId.isEmpty()) sendFriendRequest(friendId); }); builder.setNegativeButton("QR Code", (d, which) -> startActivity(new Intent(this, QRScanActivity.class))); builder.setNeutralButton("Cancel", null); builder.show(); } private void sendFriendRequest(String friendUserId) { FirebaseManager.getInstance().getUserIdsRef().child(friendUserId) .addListenerForSingleValueEvent(new ValueEventListener() { @Override public void onDataChange(DataSnapshot snapshot) { if (!snapshot.exists()) { Toast.makeText(MainActivity.this, "User not found", Toast.LENGTH_SHORT).show(); return; } String targetAuthUid = snapshot.getValue(String.class); if (targetAuthUid == null || targetAuthUid.equals(currentUid)) { Toast.makeText(MainActivity.this, "Invalid user", Toast.LENGTH_SHORT).show(); return; } FirebaseManager.getInstance().getUserRef(currentUid) .addListenerForSingleValueEvent(new ValueEventListener() { @Override public void onDataChange(DataSnapshot snap) { com.wechat.messenger.models.User me = snap.getValue(com.wechat.messenger.models.User.class); if (me == null) return; com.wechat.messenger.models.FriendRequest request = new com.wechat.messenger.models.FriendRequest(); request.setFromUserId(me.getUserId()); request.setFromAuthUid(currentUid); request.setFromName(me.getName()); request.setFromImage(me.getProfileImageBase64()); request.setToUserId(friendUserId); request.setToAuthUid(targetAuthUid); request.setStatus(com.wechat.messenger.models.FriendRequest.STATUS_PENDING); request.setTimestamp(System.currentTimeMillis()); DatabaseReference reqRef = FirebaseManager.getInstance().getFriendRequestsRef() .child(targetAuthUid).push(); String reqId = reqRef.getKey(); request.setRequestId(reqId); reqRef.setValue(request) .addOnSuccessListener(v -> Toast.makeText(MainActivity.this, "Request sent!", Toast.LENGTH_SHORT).show()) .addOnFailureListener(e -> Toast.makeText(MainActivity.this, "Failed to send request", Toast.LENGTH_SHORT).show()); } @Override public void onCancelled(DatabaseError error) {} }); } @Override public void onCancelled(DatabaseError error) {} }); } private void loadChats() { db.chatDao().getAllChats().observe(this, chats -> { allChats = chats; chatListAdapter.setChats(chats); }); listenForFirebaseChats(); } private void listenForFirebaseChats() { chatListener = FirebaseManager.getInstance().getChatsRef(currentUid) .addValueEventListener(new ValueEventListener() { @Override public void onDataChange(DataSnapshot snapshot) { new Thread(() -> { try { for (DataSnapshot chatSnap : snapshot.getChildren()) { Chat chat = chatSnap.getValue(Chat.class); if (chat == null) continue; ChatEntity entity = new ChatEntity(); entity.chatId = chat.getChatId(); entity.otherUserId = chat.getOtherUserId(); entity.otherUserName = chat.getOtherUserName(); entity.otherUserImage = chat.getOtherUserImage(); entity.lastMessage = chat.getLastMessage(); entity.lastMessageType = chat.getLastMessageType(); entity.lastMessageTime = chat.getLastMessageTime(); entity.unreadCount = chat.getUnreadCount(); entity.isOnline = chat.isOnline(); entity.lastSeen = chat.getLastSeen(); db.chatDao().insertChat(entity); } } catch (Exception e) { e.printStackTrace(); } }).start(); } @Override public void onCancelled(DatabaseError error) {} }); } private void loadContacts() { db.contactDao().getFriends().observe(this, contacts -> { contactAdapter.setContacts(contacts); }); } private void listenForFriendRequests() { FirebaseManager.getInstance().getFriendRequestsRef().child(currentUid) .orderByChild("status").equalTo(com.wechat.messenger.models.FriendRequest.STATUS_PENDING) .addValueEventListener(new ValueEventListener() { @Override public void onDataChan