ip(android.content.ClipData.newPlainText("message", message.content)); Snackbar.make(rvMessages, "Copied", Snackbar.LENGTH_SHORT).show(); } } private void setReplyTo(MessageEntity message) { replyToMessage = message; if (replyPreviewContainer != null) replyPreviewContainer.setVisibility(View.VISIBLE); if (tvReplyPreview != null) tvReplyPreview.setText(message.content != null ? message.content : ""); if (etMessage != null) etMessage.requestFocus(); } private void starMessage(MessageEntity message) { boolean newStarred = !message.isStarred; new Thread(() -> db.messageDao().setStarred(message.messageId, newStarred)).start(); FirebaseManager.getInstance().getMessagesRef(chatId) .child(message.messageId).child("isStarred").setValue(newStarred); Snackbar.make(rvMessages, newStarred ? "Starred" : "Unstarred", Snackbar.LENGTH_SHORT).show(); } private void showEditDialog(MessageEntity message) { EditText et = new EditText(this); et.setText(message.content); new android.app.AlertDialog.Builder(this) .setTitle("Edit Message") .setView(et) .setPositiveButton("Save", (d, w) -> { String newText = et.getText().toString().trim(); if (!newText.isEmpty() && !newText.equals(message.content)) { long now = System.currentTimeMillis(); new Thread(() -> db.messageDao().editMessage(message.messageId, newText, now)).start(); FirebaseManager.getInstance().getMessagesRef(chatId).child(message.messageId) .updateChildren(new HashMap<String, Object>() {{ put("content", newText); put("isEdited", true); put("editedAt", now); }}); } }) .setNegativeButton("Cancel", null).show(); } private void showDeleteDialog(MessageEntity message) { String[] opts = {"Delete for me", "Delete for everyone"}; new android.app.AlertDialog.Builder(this) .setTitle("Delete Message") .setItems(opts, (d, which) -> { if (which == 0) { new Thread(() -> db.messageDao().softDeleteMessage(message.messageId)).start(); } else { new Thread(() -> db.messageDao().softDeleteMessage(message.messageId)).start(); FirebaseManager.getInstance().getMessagesRef(chatId).child(message.messageId) .updateChildren(new HashMap<String, Object>() {{ put("isDeleted", true); put("content", ""); }}); } }).show(); } private void showForwardDialog(MessageEntity message) { Toast.makeText(this, "Forward: " + (message.content != null ? message.content : ""), Toast.LENGTH_SHORT).show(); } @Override public void onReplySwipe(MessageEntity message) { setReplyTo(message); } @Override public void onImageClick(MessageEntity message) { Intent intent = new Intent(this, ImageViewActivity.class); intent.putExtra("imageBase64", message.imageBase64); startActivity(intent); } @Override public void onRequestPermissionsResult(int requestCode, @NonNull String[] permissions, @NonNull int[] grantResults) { super.onRequestPermissionsResult(requestCode, permissions, grantResults); if (requestCode == REQUEST_AUDIO_PERMISSION && grantResults.length > 0 && grantResults[0] == PackageManager.PERMISSION_GRANTED) { startRecording(); } } @Override public boolean onCreateOptionsMenu(Menu menu) { getMenuInflater().inflate(R.menu.chat_menu, menu); return true; } @Override public boolean onOptionsItemSelected(MenuItem item) { if (item.getItemId() == R.id.action_voice_call) { startVoiceCall(); } else if (item.getItemId() == R.id.action_video_call) { startVideoCall(); } else if (item.getItemId() == R.id.action_view_profile) { viewProfile(); } return super.onOptionsItemSelected(item); } private void startVoiceCall() { Intent intent = new Intent(this, CallActivity.class); intent.putExtra("targetUid", otherUserId); intent.putExtra("targetName", otherUserName); intent.putExtra("targetImage", otherUserImage); intent.putExtra(Constants.EXTRA_IS_VIDEO, false); startActivity(intent); } private void startVideoCall() { Intent intent = new Intent(this, CallActivity.class); intent.putExtra("targetUid", otherUserId); intent.putExtra("targetName", otherUserName); intent.putExtra("targetImage", otherUserImage); intent.putExtra(Constants.EXTRA_IS_VIDEO, true); startActivity(intent); } private void viewProfile() { Intent intent = new Intent(this, ProfileActivity.class); intent.putExtra("viewUserId", otherUserId); startActivity(intent); } @Override protected void onDestroy() { super.onDestroy(); sendTypingIndicator(false); if (messageListener != null) FirebaseManager.getInstance().getMessagesRef(chatId).removeEventListener(messageListener); if (typingListener != null && otherUserId != null) FirebaseManager.getInstance().getTypingRef(chatId, otherUserId).removeEventListener(typingListener); if (onlineListener != null && otherUserId != null) FirebaseManager.getInstance().getUserRef(otherUserId).removeEventListener(onlineListener); if (mediaRecorder != null) { try { mediaRecorder.release(); } catch (Exception e) {} mediaRecorder = null; } } } EOF # ImageViewActivity (simple) cat > app/src/main/java/$PACKAGE_PATH/activities/ImageViewActivity.java <<'EOF' package com.wechat.messenger.activities; import android.os.Bundle; import android.widget.ImageView; import androidx.appcompat.app.AppCompatActivity; import com.wechat.messenger.R; import com.wechat.messenger.utils.ImageUtils; public class ImageViewActivity extends AppCompatActivity { @Override protected void onCreate(Bundle savedInstanceState) { super.onCreate(savedInstanceState); setContentView(R.layout.activity_image_view); ImageView ivImage = findViewById(R.id.ivFullImage); String base64 = getIntent().getStringExtra("imageBase64"); if (ivImage != null && base64 != null) { ImageUtils.loadBase64ImageRaw(this, base64, ivImage); } if (ivImage != null) ivImage.setOnClickListener(v -> finish()); } } EOF cat > app/src/main/java/$PACKAGE_PATH/activities/ProfileActivity.java <<'EOF' package com.wechat.messenger.activities; import android.content.Intent; import android.os.Bundle; import android.widget.*; import androidx.appcompat.app.AppCompatActivity; import androidx.appcompat.widget.Toolbar; import com.google.firebase.database.*; import com.wechat.messenger.R; import com.wechat.messenger.mo