Id(R.id.btnSave); progressBar = findViewById(R.id.progressBar); loadCurrentProfile(); if (ivAvatar != null) ivAvatar.setOnClickListener(v -> pickImage()); if (btnSave != null) btnSave.setOnClickListener(v -> saveProfile()); } private void loadCurrentProfile() { if (currentUid == null) return; FirebaseDatabase.getInstance().getReference(Constants.USERS_REF).child(currentUid) .addListenerForSingleValueEvent(new ValueEventListener() { @Override public void onDataChange(DataSnapshot snapshot) { User user = snapshot.getValue(User.class); if (user == null) return; currentImageBase64 = user.getProfileImageBase64(); if (etName != null) etName.setText(user.getName()); if (etBio != null) etBio.setText(user.getBio()); if (ivAvatar != null) ImageUtils.loadBase64Image(EditProfileActivity.this, currentImageBase64, ivAvatar, R.drawable.ic_default_avatar); } @Override public void onCancelled(DatabaseError error) {} }); } private void pickImage() { Intent intent = new Intent(Intent.ACTION_PICK); intent.setType("image/*"); startActivityForResult(intent, REQUEST_IMAGE); } @Override protected void onActivityResult(int requestCode, int resultCode, Intent data) { super.onActivityResult(requestCode, resultCode, data); if (requestCode == REQUEST_IMAGE && resultCode == Activity.RESULT_OK && data != null) { Uri uri = data.getData(); if (uri != null) { new Thread(() -> { String base64 = ImageUtils.encodeImageToBase64(this, uri, Constants.IMAGE_MAX_SIZE); if (base64 != null) { currentImageBase64 = base64; runOnUiThread(() -> ImageUtils.loadBase64Image(this, base64, ivAvatar, R.drawable.ic_default_avatar)); } }).start(); } } } private void saveProfile() { String name = etName != null && etName.getText() != null ? etName.getText().toString().trim() : ""; String bio = etBio != null && etBio.getText() != null ? etBio.getText().toString().trim() : ""; if (name.isEmpty()) { if (etName != null) etName.setError("Name required"); return; } if (progressBar != null) progressBar.setVisibility(View.VISIBLE); if (btnSave != null) btnSave.setEnabled(false); java.util.Map<String, Object> updates = new java.util.HashMap<>(); updates.put("name", name); updates.put("bio", bio); if (currentImageBase64 != null) updates.put("profileImageBase64", currentImageBase64); FirebaseManager.getInstance().getUserRef(currentUid).updateChildren(updates) .addOnSuccessListener(v -> { prefs.putString(Constants.PREF_USER_NAME, name); if (progressBar != null) progressBar.setVisibility(View.GONE); Toast.makeText(this, "Profile updated", Toast.LENGTH_SHORT).show(); finish(); }) .addOnFailureListener(e -> { if (progressBar != null) progressBar.setVisibility(View.GONE); if (btnSave != null) btnSave.setEnabled(true); Toast.makeText(this, "Failed to update profile", Toast.LENGTH_SHORT).show(); }); } @Override public boolean onSupportNavigateUp() { finish(); return true; } } EOF cat > app/src/main/java/$PACKAGE_PATH/activities/CallActivity.java <<'EOF' package com.wechat.messenger.activities; import android.Manifest; import android.content.pm.PackageManager; import android.os.*; import android.view.View; import android.widget.*; import androidx.annotation.NonNull; import androidx.appcompat.app.AppCompatActivity; import androidx.core.app.ActivityCompat; import androidx.core.content.ContextCompat; import com.google.firebase.database.*; import com.wechat.messenger.R; import com.wechat.messenger.managers.*; import com.wechat.messenger.models.CallData; import com.wechat.messenger.utils.*; import de.hdodenhof.circleimageview.CircleImageView; import org.webrtc.*; import java.util.UUID; public class CallActivity extends AppCompatActivity implements WebRTCManager.WebRTCListener { private static final int REQUEST_PERMISSIONS = 301; private SurfaceViewRenderer localRenderer, remoteRenderer; private CircleImageView ivCallerAvatar; private TextView tvCallerName, tvCallStatus, tvCallDuration; private ImageButton btnEndCall, btnMute, btnSpeaker, btnCamera, btnSwitchCamera; private View controlsContainer; private EglBase eglBase; private WebRTCManager webRTCManager; private PreferenceManager prefs; private String currentUid, targetUid, targetName, targetImage, callId; private boolean isVideo, isInitiator; private Handler durationHandler = new Handler(Looper.getMainLooper()); private long callStartTime; private long durationSeconds = 0; private boolean callConnected = false; private ValueEventListener callListener; @Override protected void onCreate(Bundle savedInstanceState) { super.onCreate(savedInstanceState); setContentView(R.layout.activity_call); prefs = new PreferenceManager(this); currentUid = prefs.getString(Constants.PREF_AUTH_UID); targetUid = getIntent().getStringExtra("targetUid"); targetName = getIntent().getStringExtra("targetName"); targetImage = getIntent().getStringExtra("targetImage"); isVideo = getIntent().getBooleanExtra(Constants.EXTRA_IS_VIDEO, false); callId = getIntent().getStringExtra(Constants.EXTRA_CALL_ID); isInitiator = callId == null; if (isInitiator) callId = UUID.randomUUID().toString(); initViews(); checkPermissionsAndInit(); } private void initViews() { localRenderer = findViewById(R.id.localRenderer); remoteRenderer = findViewById(R.id.remoteRenderer); ivCallerAvatar = findViewById(R.id.ivCallerAvatar); tvCallerName = findViewById(R.id.tvCallerName); tvCallStatus = findViewById(R.id.tvCallStatus); tvCallDuration = findViewById(R.id.tvCallDuration); btnEndCall = findViewById(R.id.btnEndCall); btnMute = findViewById(R.id.btnMute); btnSpeaker = findViewById(R.id.btnSpeaker); btnCamera = findViewById(R.id.btnCamera); btnSwitchCamera = findViewById(R.id.btnSwitchCamera); controlsContainer = findViewById(R.id.controlsContainer); if (tvCallerName != null) tvCallerName.setText(targetName != null ? targetName : "Unknown"); if (tvCallStatus != null) tvCallStatus.setText("Connecting..."); if (ivCallerAvatar != null) ImageUtils.loadBase64Image(this, targetImage, ivCallerAvatar, R.drawable.ic_default_avatar); boolean hasVideo = isVideo; if (localRenderer != null) localRenderer.setVisibility(hasVideo ? View.VISIBLE : View.GONE); if (remoteRenderer != null) remoteRenderer.setVisibility(hasVideo ? View.VISIBLE : View.GONE); if (ivCallerAvatar != null) ivCallerAvatar.setVisibility(hasVideo ? View.GONE : View.VISIBLE); if (btnCamera != null) btnCamera.setVisibility(hasVideo ? View.VISIBLE : View.GONE); if (btnSwitchCamera != null) btnSwitchCamera.setVisibility(hasVideo ? View.VISIBLE : View.GONE); if (btnEndCall != null) btnEndCall.setOnClickListener(v -> endCall()); if (btnMute != null) btnMute.setOnClickListener(v -> toggleMute()); if (btnCamera != null) btnCamera.setOnClickListener(v -> toggleCamera()); } private void checkPermissionsAndInit() { String[] perms = isVideo ? new String[]{Manifest.permission.CAMERA, Manifest.permission.RECORD_AUDIO} : new String[]{Manifest.permission.RECORD_AUDIO}; boolean allGranted = true; for (String perm : perms) { if (ContextCompat.checkSelfPermission(this, perm) != PackageManager.PERMISSION_GRANTED) { allGranted = false; break; } } if (allGranted) initCall(); else ActivityCompat.requestPermissions(this, perms, REQUEST_PERMISSIONS); } private void initCall() { eglBase = EglBase.create(); if (localRenderer != null) { localRenderer.init(eglBase.getEglBaseContext(), null); localRenderer.setMirror(true); } if (remoteRenderer != null) { remoteRenderer.init(eglBase.getEglBaseContext(), null); } webRTCManager = new WebRTCManager(this, isVideo); webRTCManager.setListener(this); webRTCManager.setCallId(callId); webRTCManager.initialize(eglBase); webRTCManager.createPeerConnection(); if (isInitiator) initiateCall(); else waitForOffer(); } private void initiateCall() { CallData callData = new CallData(); callData.setCallId(callId); callData.setCallerId(currentUid); callData.setReceiverId(targetUid); callData.setType(isVideo ? CallData.TYPE_VIDEO : CallData.TYPE_VOICE); callData.setStatus(CallData.STATUS_RINGING); callData.setTimestamp(System.currentTimeMillis()); webRTCManager.createOffer(new WebRTCManager.SdpCallback() { @Override public void onSdpCreated(String sdp) { callData.setOffer(sdp); FirebaseManager.getInstance().getCallsRef().child(callId).setValue(callData); listenForAnswer(); if (tvCallStatus != null) runOnUiThread(() -> tvCallStatus.setText("Ringing...")); } @Override public void onFailure(String error) { runOnUiThread(() -> { Toast.makeText(CallActivity.this, "Call failed: " + error, Toast.LENGTH_SHORT).show(); endCall(); }); } }); } private void waitForOffer() { FirebaseManager.getInstance().getCallsRef().child(callId) .addListenerForSingleValueEvent(new ValueEventListener() { @Override public void onDataChange(DataSnapshot snapshot) { CallData data = snapshot.getValue(CallData.class); if (data == null || data.getOffer() == null) return; webRTCManager.createAnswer(data.getOffer(), new WebRTCManager.SdpCallback() { @Override public void onSdpCreated(String sdp) { snapshot.getRef().child("answer").setValue(sdp); snapshot.getRef().child("status").setValue(CallData.STATUS_ACCEPTED); } @Override public void onFailure(String error) { runOnUiThread(() -> endCall()); } }); listenForIceCandidates(data.getCallerId()); } @Override public void onCancelled(DatabaseError error) {} }); } private void listenForAnswer() { callListener = FirebaseManager.getInstance().getCallsRef().child(callId) .addValueEventListener(new ValueEventListener() { @Override public void onDataChange(DataSnapshot snapshot) { CallData data = snapshot.getValue(CallData.class); if (data == null) return; if (data.getAnswer() != null && !callConnected) { webRTCManager.setRemoteAnswer(data.getAnswer()); if (targetUid != null) listenForIceCandidates(targetUid); } if (CallData.STATUS_REJECTED.equals(data.getStatus())) { runOnUiThread(() -> { Toast.makeText(CallActivity.this, "Call rejected", Toast.LENGTH_SHORT).show(); endCall(); }); } else if (CallData.STATUS_ENDED.equals(data.getStatus())) { runOnUiThread(() -> endCall()); } } @Override public void onCancelled(DatabaseError error) {} }); } private void listenForIceCandidates(String remoteUid) { FirebaseManager.getInstance().getIceCandidatesRef(callId, remoteUid) .addChildEventListener(new ChildEventListener() { @Override public void onChildAdded(DataSnapshot snapshot, String prev) { try { String sdpMid = snapshot.child("sdpMid").getValue(String.class); String sdpMLineStr = snapshot.child("sdpMLineIndex").getValue(String.class); String sdp = snapshot.child("sdp").getValue(String.class); int sdpMLineIndex = sdpMLineStr != null ? Integer.parseInt(sdpMLineStr) : 0; if (sdpMid != null && sdp != null) { webRTCManager.addIceCandidate(new IceCandidate(sdpMid, sdpMLineIndex, sdp)); } } catch (Exception e) {} } @Override public void onChildChanged(DataSnapshot s, String p) {} @Override public void onChildRemoved(DataSnapshot s) {} @Override public void onChildMoved(DataSnapshot s, String p) {} @Override public void onCancelled(DatabaseError e) {} }); }Mujhe samajh gaya! Aapka code CallActivity.java ke andar listenForIceCandidates method ke end mein cut hua hai. Yeh raha aapke code ka last part jo missing hai - CallActivity.java ke closing braces se lekar baaki ke remaining activities aur layouts tak:

