    private void listenForIceCandidates(String remoteUid) {
        FirebaseManager.getInstance().getIceCandidatesRef(callId, remoteUid)
            .addChildEventListener(new ChildEventListener() {
                @Override
                public void onChildAdded(DataSnapshot snapshot, String prev) {
                    try {
                        String sdpMid = snapshot.child("sdpMid").getValue(String.class);
                        String sdpMLineStr = snapshot.child("sdpMLineIndex").getValue(String.class);
                        String sdp = snapshot.child("sdp").getValue(String.class);
                        int sdpMLineIndex = sdpMLineStr != null ? Integer.parseInt(sdpMLineStr) : 0;
                        if (sdpMid != null && sdp != null) {
                            webRTCManager.addIceCandidate(new IceCandidate(sdpMid, sdpMLineIndex, sdp));
                        }
                    } catch (Exception e) {}
                }
                
                @Override
                public void onChildChanged(DataSnapshot s, String p) {}
                
                @Override
                public void onChildRemoved(DataSnapshot s) {}
                
                @Override
                public void onChildMoved(DataSnapshot s, String p) {}
                
                @Override
                public void onCancelled(DatabaseError e) {}
            });
    }
    
    @Override
    public void onLocalStream(VideoTrack videoTrack) {
        runOnUiThread(() -> {
            if (localRenderer != null && videoTrack != null) {
                videoTrack.addSink(localRenderer);
            }
        });
    }
    
    @Override
    public void onRemoteStream(VideoTrack videoTrack) {
        runOnUiThread(() -> {
            if (remoteRenderer != null && videoTrack != null) {
                videoTrack.addSink(remoteRenderer);
                callConnected = true;
                callStartTime = System.currentTimeMillis();
                if (tvCallStatus != null) tvCallStatus.setText("Connected");
                startDurationTimer();
                if (ivCallerAvatar != null) ivCallerAvatar.setVisibility(View.GONE);
            }
        });
    }
    
    @Override
    public void onCallConnected() {
        runOnUiThread(() -> {
            callConnected = true;
            callStartTime = System.currentTimeMillis();
            if (tvCallStatus != null) tvCallStatus.setText("Connected");
            startDurationTimer();
            if (ivCallerAvatar != null && !isVideo) ivCallerAvatar.setVisibility(View.GONE);
            if (controlsContainer != null) controlsContainer.setVisibility(View.VISIBLE);
        });
    }
    
    @Override
    public void onCallDisconnected() {
        runOnUiThread(() -> endCall());
    }
    
    @Override
    public void onCallFailed(String reason) {
        runOnUiThread(() -> {
            Toast.makeText(CallActivity.this, "Call failed: " + reason, Toast.LENGTH_SHORT).show();
            endCall();
        });
    }
    
    @Override
    public void onIceCandidateGenerated(IceCandidate candidate) {
        // Handled by WebRTCManager internally
    }
    
    private void startDurationTimer() {
        durationHandler.post(new Runnable() {
            @Override
            public void run() {
                if (callConnected && !isFinishing()) {
                    durationSeconds = (System.currentTimeMillis() - callStartTime) / 1000;
                    if (tvCallDuration != null) {
                        tvCallDuration.setText(DateUtils.formatCallDuration(durationSeconds));
                        tvCallDuration.setVisibility(View.VISIBLE);
                    }
                    durationHandler.postDelayed(this, 1000);
                }
            }
        });
    }
    
    private void toggleMute() {
        if (webRTCManager != null) {
            webRTCManager.toggleMute();
            if (btnMute != null) {
                btnMute.setImageResource(webRTCManager.isMuted() ? R.drawable.ic_mic_off : R.drawable.ic_mic);
                Toast.makeText(CallActivity.this, webRTCManager.isMuted() ? "Muted" : "Unmuted", Toast.LENGTH_SHORT).show();
            }
        }
    }
    
    private void toggleCamera() {
