            webRTCManager.toggleCamera();
            if (btnCamera != null) {
                btnCamera.setImageResource(webRTCManager.isCameraOff() ? R.drawable.ic_videocam_off : R.drawable.ic_videocam);
            }
        }
    }
    
    private void endCall() {
        durationHandler.removeCallbacksAndMessages(null);
        
        if (callId != null && !isFinishing()) {
            if (callConnected && callStartTime > 0) {
                try {
                    long duration = (System.currentTimeMillis() - callStartTime) / 1000;
                    if (duration >= 1) {
                        FirebaseManager.getInstance().getCallsRef().child(callId).child("duration").setValue(duration);
                    }
                } catch (Exception e) {}
            }
            
            try {
                DatabaseReference callRef = FirebaseManager.getInstance().getCallsRef().child(callId);
                callRef.child("status").setValue(CallData.STATUS_ENDED);
            } catch (Exception e) {}
        }
        
        if (callListener != null && callId != null) {
            FirebaseManager.getInstance().getCallsRef().child(callId).removeEventListener(callListener);
        }
        
        if (webRTCManager != null) {
            webRTCManager.release();
        }
        
        if (eglBase != null) {
            eglBase.release();
        }
        
        finish();
    }
    
    @Override
    public void onRequestPermissionsResult(int requestCode, @NonNull String[] permissions, @NonNull int[] grantResults) {
        super.onRequestPermissionsResult(requestCode, permissions, grantResults);
        boolean allGranted = true;
        for (int result : grantResults) {
            if (result != PackageManager.PERMISSION_GRANTED) {
                allGranted = false;
                break;
            }
        }
        if (allGranted) {
            initCall();
        } else {
            Toast.makeText(this, "Permissions required for calls", Toast.LENGTH_SHORT).show();
            endCall();
        }
    }
    
    @Override
    protected void onDestroy() {
        super.onDestroy();
        durationHandler.removeCallbacksAndMessages(null);
        if (webRTCManager != null) {
            webRTCManager.release();
        }
        if (callListener != null && callId != null) {
            FirebaseManager.getInstance().getCallsRef().child(callId).removeEventListener(callListener);
        }
    }
}
EOF

# ─── INCOMING CALL ACTIVITY ─────────────────────────────────────────────────────
cat > app/src/main/java/$PACKAGE_PATH/activities/IncomingCallActivity.java <<'EOF'
package com.wechat.messenger.activities;

import android.content.Intent;
import android.os.Bundle;
import android.os.Vibrator;
import android.view.WindowManager;
import android.widget.Button;
import android.widget.TextView;
import androidx.appcompat.app.AppCompatActivity;
import com.google.firebase.database.*;
import com.wechat.messenger.R;
import com.wechat.messenger.models.CallData;
import com.wechat.messenger.utils.Constants;
import de.hdodenhof.circleimageview.CircleImageView;

public class IncomingCallActivity extends AppCompatActivity {
    
    private CircleImageView ivCallerAvatar;
    private TextView tvCallerName, tvCallType;
    private Button btnAccept, btnReject;
    private Vibrator vibrator;
    private String callId, callerName, callType, targetUid;
    private boolean isVideo;
    private ValueEventListener callListener;
    
    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_incoming_call);
        
        getWindow().addFlags(WindowManager.LayoutParams.FLAG_SHOW_WHEN_LOCKED
                | WindowManager.LayoutParams.FLAG_TURN_SCREEN_ON
                | WindowManager.LayoutParams.FLAG_KEEP_SCREEN_ON);
        
        ivCallerAvatar = findViewById(R.id.ivCallerAvatar);
        tvCallerName = findViewById(R.id.tvCallerName);
        tvCallType = findViewById(R.id.tvCallType);
        btnAccept = findViewById(R.id.btnAccept);
        btnReject = findViewById(R.id.btnReject);
        
        callId = getIntent().getStringExtra(Constants.EXTRA_CALL_ID);
        callerName = getIntent().getStringExtra("callerName");
        callType = getIntent().getStringExtra("callType");
        targetUid = getIntent().getStringExtra("targetUid");
        isVideo = "video".equals(callType);
        
        if (tvCallerName != null) tvCallerName.setText(callerName != null ? callerName : "Unknown");
        if (tvCallType != null) tvCallType.setText("Incoming " + (callType != null ? callType : "Voice") + " Call");
        
        startVibration();
        
        btnAccept.setOnClickListener(v -> acceptCall());
        btnReject.setOnClickListener(v -> rejectCall());
        
        listenForCallStatus();
    }
    
    private void startVibration() {
        vibrator = (Vibrator) getSystemService(VIBRATOR_SERVICE);
        if (vibrator != null && vibrator.hasVibrator()) {
            long[] pattern = {0, 1000, 500};
            vibrator.vibrate(pattern, 0);
        }
    }
    
    private void listenForCallStatus() {
        if (callId == null) return;
        callListener = FirebaseDatabase.getInstance().getReference(Constants.CALLS_REF)
            .child(callId)
            .addValueEventListener(new ValueEventListener() {
                @Override
                public void onDataChange(DataSnapshot snapshot) {
                    CallData data = snapshot.getValue(CallData.class);
                    if (data != null && (CallData.STATUS_ENDED.equals(data.getStatus()) 
                            || CallData.STATUS_REJECTED.equals(data.getStatus()))) {
                        stopVibration();
                        finish();
                    }
                }
                
                @Override
                public void onCancelled(DatabaseError error) {
                    finish();
                }
            });
    }
    
    private void acceptCall() {
        stopVibration();
        Intent intent = new Intent(this, CallActivity.class);
        intent.putExtra(Constants.EXTRA_CALL_ID, callId);
        intent.putExtra("targetUid", targetUid);
        intent.putExtra("targetName", callerName);
        intent.putExtra(Constants.EXTRA_IS_VIDEO, isVideo);
        intent.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK);
        startActivity(intent);
        finish();
    }
    
    private void rejectCall() {
        stopVibration();
        if (callId != null) {
            FirebaseDatabase.getInstance().getReference(Constants.CALLS_REF)
                .child(callId).child("status").setValue(CallData.STATUS_REJECTED);
        }
        finish();
    }
    
    private void stopVibration() {
        if (vibrator != null) {
            vibrator.cancel();
        }
    }
    
    @Override
    protected void onDestroy() {
        super.onDestroy();
        stopVibration();
        if (callListener != null && callId != null) {
            FirebaseDatabase.getInstance().getReference(Constants.CALLS_REF)
                .child(callId).removeEventListener(callListener);
        }
    }
}
EOF

